import type { HandbookDocumentContent } from "../types";

const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">ENGINEERING · JAVA SPRING</div>\n  <div class=\"nav-title\">Java Spring JPA 실전 사례</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>통합 문서</a>\n  <a href=\"#doc-java\"><span class=\"code\">DOC</span>Java 예시</a>\n  <a href=\"#doc-jpa\"><span class=\"code\">DOC</span>JPA 예시</a>\n  <a href=\"#doc-spring\"><span class=\"code\">DOC</span>Spring Boot 예시</a>\n  <a href=\"#doc-java\"><span class=\"code\">SRC</span>Java 예시</a>\n<a href=\"#java-ch1\"><span class=\"code\">JAVA-01</span>변수·타입·var</a>\n  <a href=\"#java-ch2\"><span class=\"code\">JAVA-02</span>컬렉션</a>\n  <a href=\"#java-ch3\"><span class=\"code\">JAVA-03</span>스트림 API</a>\n  <a href=\"#java-ch4\"><span class=\"code\">JAVA-04</span>Optional</a>\n  <a href=\"#java-ch5\"><span class=\"code\">JAVA-05</span>record와 불변 객체</a>\n  <a href=\"#java-ch6\"><span class=\"code\">JAVA-06</span>예외 처리</a>\n  <a href=\"#java-ch7\"><span class=\"code\">JAVA-07</span>제네릭</a>\n  <a href=\"#java-ch8\"><span class=\"code\">JAVA-08</span>동시성 기초</a>\n  <a href=\"#java-ch9\"><span class=\"code\">JAVA-09</span>날짜·시간</a>\n  <a href=\"#java-ch10\"><span class=\"code\">JAVA-10</span>자주 쓰는 이디엄</a>\n  <a href=\"#java-ch11\"><span class=\"code\">JAVA-11</span>치트시트</a>\n  <a href=\"#doc-jpa\"><span class=\"code\">SRC</span>JPA 예시</a>\n<a href=\"#jpa-ch1\"><span class=\"code\">JPA-01</span>엔티티 기본</a>\n  <a href=\"#jpa-ch2\"><span class=\"code\">JPA-02</span>연관관계 매핑</a>\n  <a href=\"#jpa-ch3\"><span class=\"code\">JPA-03</span>Repository</a>\n  <a href=\"#jpa-ch4\"><span class=\"code\">JPA-04</span>JPQL과 @Query</a>\n  <a href=\"#jpa-ch5\"><span class=\"code\">JPA-05</span>N+1 해결</a>\n  <a href=\"#jpa-ch6\"><span class=\"code\">JPA-06</span>페이징·정렬</a>\n  <a href=\"#jpa-ch7\"><span class=\"code\">JPA-07</span>트랜잭션·영속성</a>\n  <a href=\"#jpa-ch8\"><span class=\"code\">JPA-08</span>낙관적 락</a>\n  <a href=\"#jpa-ch9\"><span class=\"code\">JPA-09</span>Auditing</a>\n  <a href=\"#jpa-ch10\"><span class=\"code\">JPA-10</span>치트시트</a>\n  <a href=\"#jpa-ch11\"><span class=\"code\">JPA-11</span>프록시·flush·연관관계 심화</a>\n  <a href=\"#doc-spring\"><span class=\"code\">SRC</span>Spring Boot 예시</a>\n<a href=\"#spring-ch1\"><span class=\"code\">SPRING-01</span>프로젝트 구조와 시작</a>\n  <a href=\"#spring-ch2\"><span class=\"code\">SPRING-02</span>REST 컨트롤러</a>\n  <a href=\"#spring-ch3\"><span class=\"code\">SPRING-03</span>DI와 빈</a>\n  <a href=\"#spring-ch4\"><span class=\"code\">SPRING-04</span>설정</a>\n  <a href=\"#spring-ch5\"><span class=\"code\">SPRING-05</span>서비스·트랜잭션</a>\n  <a href=\"#spring-ch6\"><span class=\"code\">SPRING-06</span>예외 처리</a>\n  <a href=\"#spring-ch7\"><span class=\"code\">SPRING-07</span>요청 검증</a>\n  <a href=\"#spring-ch8\"><span class=\"code\">SPRING-08</span>데이터 접근 연동</a>\n  <a href=\"#spring-ch9\"><span class=\"code\">SPRING-09</span>테스트</a>\n  <a href=\"#spring-ch10\"><span class=\"code\">SPRING-10</span>운영 — Actuator</a>\n  <a href=\"#spring-ch11\"><span class=\"code\">SPRING-11</span>치트시트</a>\n  <a href=\"#spring-ch12\"><span class=\"code\">SPRING-12</span>프록시·트랜잭션·테스트 심화</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : ENGINEERING-JAVA-SPRING</span>\n    <span>SCOPE : JAVA · SPRING BOOT · JPA</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>Java·Spring·JPA 사례</h1>\n  <p class=\"hero-sub\">Java 예시, JPA 예시, Spring Boot 예시를 백엔드 구현 사례 중심으로 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED HANDBOOK PATH · SOURCES : 3 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>통합 문서</h2></div>\n<p class=\"lede\">아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다.</p>\n<ul><li>Java 예시</li><li>JPA 예시</li><li>Spring Boot 예시</li></ul>\n</section>\n\n<section id=\"doc-java\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Java 예시</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : JAVA-EXAMPLES-V1</span>\n    <span>STACK : JAVA 17+</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>Java<br>예시 사례</h1>\n  <p class=\"hero-sub\">개념이 아니라 바로 쓰는 코드 — JS/TS 하던 손에 Java 문법을 붙이는 레시피. 각 섹션은 \"언제·왜\" 한두 줄과 복붙해서 고쳐 쓸 코드 카드로 구성됩니다. Java 17+ 기준.</p>\n  <div class=\"hero-meta\">NOTE : JS/TS와 대비되는 지점은 본문에 한 줄로 표시<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"java-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-01</span><h2>변수·타입·var</h2></div>\n<p class=\"lede\">Java는 정적 타입 언어 — 변수마다 타입이 박힙니다. 핵심 구분 하나: <em>기본형(primitive)</em>은 값 자체를, <em>참조형(reference)</em>은 객체 주소를 담습니다. JS의 <code>let</code>/<code>const</code>와 대비하면 감이 빨리 잡힙니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">PRIMITIVE vs REFERENCE</span><br>\n<span class=\"dim\">// 기본형 — 값을 직접 담음 (소문자로 시작)</span><br>\n<span class=\"seg2\">int</span> count = <span class=\"seg\">10</span>;<br>\n<span class=\"seg2\">long</span> big = <span class=\"seg\">9_000_000_000L</span>;   <span class=\"dim\">// L 접미사, _ 가독성</span><br>\n<span class=\"seg2\">double</span> price = <span class=\"seg\">19.99</span>;<br>\n<span class=\"seg2\">boolean</span> active = <span class=\"seg\">true</span>;<br>\n<span class=\"seg2\">char</span> grade = <span class=\"seg\">'A'</span>;<br>\n<br>\n<span class=\"dim\">// 참조형 — 객체 (대문자로 시작, null 가능)</span><br>\n<span class=\"seg2\">String</span> name = <span class=\"seg\">\"haeun\"</span>;<br>\n<span class=\"seg2\">Integer</span> boxed = <span class=\"seg\">42</span>;          <span class=\"dim\">// int의 객체 wrapper, null 가능</span><br>\n<span class=\"seg2\">int[]</span> nums = {<span class=\"seg\">1</span>, <span class=\"seg\">2</span>, <span class=\"seg\">3</span>};\n</div>\n<p><code>int</code>은 절대 <code>null</code>이 될 수 없지만 <code>Integer</code>(wrapper)는 가능합니다. DB 컬럼이 nullable이면 entity 필드는 <code>Integer</code>/<code>Long</code>을 씁니다 — 여기서 JS 출신이 자주 헷갈립니다.</p>\n<h3><span class=\"h3-tag\">1.1</span>var 타입 추론 · final</h3>\n<p>Java 10+의 <code>var</code>는 TS의 타입 추론과 비슷하지만, <em>지역 변수에서만</em> 쓸 수 있고 우변으로 타입이 즉시 정해집니다(런타임 동적 타입이 아님). <code>final</code>은 JS의 <code>const</code>에 해당 — 재할당 금지.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">var &amp; final</span><br>\n<span class=\"seg2\">var</span> users = <span class=\"seg2\">new</span> ArrayList&lt;String&gt;();  <span class=\"dim\">// ArrayList&lt;String&gt;로 추론</span><br>\n<span class=\"seg2\">var</span> total = <span class=\"seg\">0</span>;                       <span class=\"dim\">// int로 추론</span><br>\n<br>\n<span class=\"seg2\">final</span> <span class=\"seg2\">int</span> MAX = <span class=\"seg\">100</span>;                  <span class=\"dim\">// 재할당 불가 (= JS const)</span><br>\n<span class=\"seg2\">final</span> <span class=\"seg2\">var</span> config = loadConfig();      <span class=\"dim\">// final + var 조합 가능</span><br>\n<span class=\"dim\">// MAX = 200;  →  컴파일 에러</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">var 주의</span>\n<p><code>var x;</code>처럼 초기값 없이 선언하거나, 필드(클래스 멤버)·메서드 파라미터·리턴 타입에는 <code>var</code>를 못 씁니다. 우변이 타입을 명확히 드러내지 않으면(예: <code>var x = null;</code>) 컴파일 에러입니다. JS의 <code>let x;</code> 감각으로 쓰면 막힙니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"java-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-02</span><h2>컬렉션</h2></div>\n<p class=\"lede\">JS의 배열·Map·Set이 Java에선 <code>List</code>·<code>Map</code>·<code>Set</code> 인터페이스로 나뉩니다. 인터페이스(<code>List</code>)로 선언하고 구현체(<code>ArrayList</code>)로 생성하는 게 관례입니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">생성 — 수정 가능 vs 불변</span><br>\n<span class=\"dim\">// 수정 가능한 빈 리스트</span><br>\nList&lt;String&gt; names = <span class=\"seg2\">new</span> ArrayList&lt;&gt;();<br>\nnames.add(<span class=\"seg\">\"kim\"</span>);<br>\nnames.add(<span class=\"seg\">\"lee\"</span>);<br>\n<br>\n<span class=\"dim\">// 불변 리스트 — add 하면 UnsupportedOperationException</span><br>\nList&lt;String&gt; fixed = List.of(<span class=\"seg\">\"a\"</span>, <span class=\"seg\">\"b\"</span>, <span class=\"seg\">\"c\"</span>);<br>\n<br>\n<span class=\"dim\">// Map / Set</span><br>\nMap&lt;String, Integer&gt; scores = <span class=\"seg2\">new</span> HashMap&lt;&gt;();<br>\nscores.put(<span class=\"seg\">\"haeun\"</span>, <span class=\"seg\">95</span>);<br>\nMap&lt;String, Integer&gt; m = Map.of(<span class=\"seg\">\"x\"</span>, <span class=\"seg\">1</span>, <span class=\"seg\">\"y\"</span>, <span class=\"seg\">2</span>);  <span class=\"dim\">// 불변</span><br>\nSet&lt;String&gt; tags = <span class=\"seg2\">new</span> HashSet&lt;&gt;(List.of(<span class=\"seg\">\"order\"</span>, <span class=\"seg\">\"payment\"</span>));\n</div>\n<h3><span class=\"h3-tag\">2.1</span>순회</h3>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">ITERATION</span><br>\n<span class=\"dim\">// List 순회 — for-each (JS for...of)</span><br>\n<span class=\"seg2\">for</span> (String name : names) {<br>\n&nbsp;&nbsp;System.out.println(name);<br>\n}<br>\nnames.forEach(System.out::println);  <span class=\"dim\">// 메서드 참조</span><br>\n<br>\n<span class=\"dim\">// Map 순회 — entrySet (JS for...of Object.entries)</span><br>\n<span class=\"seg2\">for</span> (Map.Entry&lt;String, Integer&gt; e : scores.entrySet()) {<br>\n&nbsp;&nbsp;System.out.println(e.getKey() + <span class=\"seg\">\" = \"</span> + e.getValue());<br>\n}<br>\nscores.forEach((key, value) -&gt; System.out.println(key + value));\n</div>\n<table>\n<tr><th>자주 쓰는 메서드</th><th>의미 / JS 대응</th></tr>\n<tr><td><code>list.size()</code></td><td>크기 (JS <code>arr.length</code>)</td></tr>\n<tr><td><code>list.get(0)</code> / <code>list.set(0, v)</code></td><td>인덱스 접근/수정 (<code>arr[0]</code>)</td></tr>\n<tr><td><code>list.contains(v)</code></td><td>포함 여부 (<code>arr.includes</code>)</td></tr>\n<tr><td><code>list.isEmpty()</code></td><td>비었는지 (<code>arr.length === 0</code>)</td></tr>\n<tr><td><code>map.getOrDefault(k, def)</code></td><td>없으면 기본값 (<code>map.get(k) ?? def</code>)</td></tr>\n<tr><td><code>map.computeIfAbsent(k, x -&gt; ...)</code></td><td>없을 때만 계산해 넣고 반환</td></tr>\n<tr><td><code>map.containsKey(k)</code></td><td>키 존재 여부 (<code>k in obj</code>)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">선택 기준</span>\n<p>순서 유지가 필요하면 <code>ArrayList</code>, 중복 제거는 <code>HashSet</code>, 키-값은 <code>HashMap</code>. 입력 순서를 보존하는 Map이 필요하면 <code>LinkedHashMap</code>. <code>List.of()</code>/<code>Map.of()</code>로 만든 건 <strong>불변</strong>이라 나중에 수정할 거면 <code>new ArrayList&lt;&gt;(List.of(...))</code>로 감싸세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"java-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-03</span><h2>스트림 API</h2></div>\n<p class=\"lede\">JS의 <code>.filter().map().reduce()</code> 체이닝이 Java에선 Stream입니다. 차이 하나: 컬렉션에 <code>.stream()</code>으로 진입하고, <code>.collect()</code>로 빠져나와야 결과가 나옵니다(lazy).</p>\n<pre class=\"snippet-card\">\n<span class=\"sc-label\">filter · map · collect</span>\n<span class=\"dim\">// JS: users.filter(u =&gt; u.age &gt;= 18).map(u =&gt; u.name)</span><br>\nList&lt;String&gt; adults = users.stream()<br>\n&nbsp;&nbsp;.filter(u -&gt; u.age() &gt;= <span class=\"seg\">18</span>)<br>\n&nbsp;&nbsp;.map(User::name)<br>\n&nbsp;&nbsp;.collect(Collectors.toList());<br>\n<br>\n<span class=\"dim\">// Java 16+ : .toList() 로 더 짧게 (불변 리스트 반환)</span><br>\nList&lt;String&gt; names = users.stream().map(User::name).toList();\n</pre>\n<h3><span class=\"h3-tag\">3.1</span>reduce · groupingBy</h3>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">집계</span><br>\n<span class=\"dim\">// 합계 — JS reduce((a, b) =&gt; a + b, 0)</span><br>\n<span class=\"seg2\">int</span> totalAge = users.stream()<br>\n&nbsp;&nbsp;.mapToInt(User::age)<br>\n&nbsp;&nbsp;.sum();<br>\n<br>\n<span class=\"seg2\">int</span> product = nums.stream().reduce(<span class=\"seg\">1</span>, (a, b) -&gt; a * b);<br>\n<br>\n<span class=\"dim\">// 그룹핑 — Map&lt;도시, List&lt;User&gt;&gt; (JS엔 기본 내장 없음)</span><br>\nMap&lt;String, List&lt;User&gt;&gt; byCity = users.stream()<br>\n&nbsp;&nbsp;.collect(Collectors.groupingBy(User::city));<br>\n<br>\n<span class=\"dim\">// 그룹별 개수 — Map&lt;도시, Long&gt;</span><br>\nMap&lt;String, Long&gt; countByCity = users.stream()<br>\n&nbsp;&nbsp;.collect(Collectors.groupingBy(User::city, Collectors.counting()));\n</div>\n<table>\n<tr><th>Stream 연산</th><th>JS 배열 대응</th></tr>\n<tr><td><code>.filter(p)</code></td><td><code>.filter()</code></td></tr>\n<tr><td><code>.map(f)</code></td><td><code>.map()</code></td></tr>\n<tr><td><code>.sorted()</code> / <code>.sorted(comparator)</code></td><td><code>.sort()</code></td></tr>\n<tr><td><code>.distinct()</code></td><td><code>[...new Set(arr)]</code></td></tr>\n<tr><td><code>.limit(n)</code> / <code>.skip(n)</code></td><td><code>.slice()</code></td></tr>\n<tr><td><code>.anyMatch(p)</code> / <code>.allMatch(p)</code></td><td><code>.some()</code> / <code>.every()</code></td></tr>\n<tr><td><code>.findFirst()</code></td><td><code>.find()</code> (Optional 반환)</td></tr>\n<tr><td><code>.count()</code></td><td><code>.length</code> (필터 후)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">스트림은 일회용</span>\n<p>한 번 소비한 Stream은 재사용 못 합니다 — 두 번 <code>.collect()</code>하면 <code>IllegalStateException</code>. 또 <code>.stream()</code>만 호출하고 terminal 연산(<code>collect</code>/<code>forEach</code>/<code>count</code> 등)을 안 붙이면 <em>아무 일도 일어나지 않습니다</em>(lazy). JS 배열 메서드처럼 매번 새 배열을 즉시 반환하는 게 아닙니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"java-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-04</span><h2>Optional</h2></div>\n<p class=\"lede\">\"값이 있을 수도, 없을 수도\" 를 타입으로 표현 — JS의 <code>?.</code>/<code>??</code>가 메서드로 들어온 형태입니다. <code>null</code> 체크를 강제해 NPE를 줄입니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">생성 &amp; 꺼내기</span><br>\n<span class=\"dim\">// 생성</span><br>\nOptional&lt;User&gt; found = repo.findById(<span class=\"seg\">1L</span>);  <span class=\"dim\">// 보통 라이브러리가 반환</span><br>\nOptional&lt;String&gt; opt = Optional.ofNullable(maybeNull);<br>\n<br>\n<span class=\"dim\">// 기본값 — JS: maybeNull ?? \"guest\"</span><br>\nString name = opt.orElse(<span class=\"seg\">\"guest\"</span>);<br>\nString lazy = opt.orElseGet(() -&gt; computeDefault());  <span class=\"dim\">// 필요할 때만 계산</span><br>\n<br>\n<span class=\"dim\">// 없으면 예외 던지기</span><br>\nUser user = found.orElseThrow(() -&gt; <span class=\"seg2\">new</span> NotFoundException(<span class=\"seg\">\"없음\"</span>));\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">map · ifPresent — chaining</span><br>\n<span class=\"dim\">// JS: user?.profile?.email ?? \"no-email\"</span><br>\nString email = found<br>\n&nbsp;&nbsp;.map(User::profile)<br>\n&nbsp;&nbsp;.map(Profile::email)<br>\n&nbsp;&nbsp;.orElse(<span class=\"seg\">\"no-email\"</span>);<br>\n<br>\n<span class=\"dim\">// 값이 있을 때만 실행 — JS: if (x != null) {...}</span><br>\nfound.ifPresent(u -&gt; System.out.println(u.name()));<br>\nfound.ifPresentOrElse(<br>\n&nbsp;&nbsp;u -&gt; log.info(<span class=\"seg\">\"찾음: \"</span> + u.name()),<br>\n&nbsp;&nbsp;() -&gt; log.warn(<span class=\"seg\">\"못 찾음\"</span>)<br>\n);\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">안티패턴 — Optional.get()</span>\n<p><code>opt.get()</code>은 값이 없으면 <code>NoSuchElementException</code>을 던집니다 — <code>opt.isPresent()</code>로 먼저 확인하지 않고 <code>get()</code>을 부르는 건 NPE를 다른 예외로 바꾼 것뿐입니다. <code>orElse</code>/<code>orElseThrow</code>/<code>map</code>으로 처리하세요. 그리고 Optional은 <em>리턴 타입용</em>입니다 — 필드나 메서드 파라미터에 쓰지 마세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"java-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-05</span><h2>record와 불변 객체</h2></div>\n<p class=\"lede\">데이터만 담는 클래스(DTO, value object)는 <code>record</code> 한 줄이면 끝 — 생성자·getter·<code>equals</code>·<code>hashCode</code>·<code>toString</code>이 자동 생성됩니다. TS의 <code>readonly</code> 객체 타입에 가깝습니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">RECORD — 한 줄 불변 객체</span><br>\n<span class=\"dim\">// 이게 전부. 필드는 자동 final, getter는 name() 형태</span><br>\n<span class=\"seg2\">public record</span> User(String name, <span class=\"seg2\">int</span> age, String city) {}<br>\n<br>\n<span class=\"dim\">// 사용</span><br>\n<span class=\"seg2\">var</span> u = <span class=\"seg2\">new</span> User(<span class=\"seg\">\"haeun\"</span>, <span class=\"seg\">31</span>, <span class=\"seg\">\"gwangmyeong\"</span>);<br>\nu.name();   <span class=\"dim\">// \"haeun\"  (getName 아님 — name())</span><br>\nu.age();    <span class=\"dim\">// 31</span><br>\n<span class=\"dim\">// u.age = 32;  →  불가능 (불변)</span><br>\n<br>\n<span class=\"dim\">// 검증·정규화는 compact 생성자에</span><br>\n<span class=\"seg2\">public record</span> Credit(String id, <span class=\"seg2\">int</span> amount) {<br>\n&nbsp;&nbsp;<span class=\"seg2\">public</span> Credit {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">if</span> (amount &lt; <span class=\"seg\">0</span>) <span class=\"seg2\">throw new</span> IllegalArgumentException(<span class=\"seg\">\"음수 불가\"</span>);<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<h3><span class=\"h3-tag\">5.1</span>빌더 패턴</h3>\n<p>필드가 많거나 선택적 값이 섞이면 생성자 인자 순서가 헷갈립니다. 이때 빌더로 \"이름 붙은 인자\"처럼 씁니다(JS의 옵션 객체 <code>{name, age}</code> 감각).</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">BUILDER</span><br>\n<span class=\"seg2\">public class</span> Order {<br>\n&nbsp;&nbsp;<span class=\"seg2\">private final</span> String id;<br>\n&nbsp;&nbsp;<span class=\"seg2\">private final</span> <span class=\"seg2\">int</span> qty;<br>\n&nbsp;&nbsp;<span class=\"seg2\">private final</span> String memo;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">private</span> Order(Builder b) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">this</span>.id = b.id; <span class=\"seg2\">this</span>.qty = b.qty; <span class=\"seg2\">this</span>.memo = b.memo;<br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">public static class</span> Builder {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">private</span> String id;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">private</span> <span class=\"seg2\">int</span> qty = <span class=\"seg\">1</span>;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">private</span> String memo = <span class=\"seg\">\"\"</span>;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">public</span> Builder id(String v){ <span class=\"seg2\">this</span>.id = v; <span class=\"seg2\">return this</span>; }<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">public</span> Builder qty(<span class=\"seg2\">int</span> v){ <span class=\"seg2\">this</span>.qty = v; <span class=\"seg2\">return this</span>; }<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">public</span> Builder memo(String v){ <span class=\"seg2\">this</span>.memo = v; <span class=\"seg2\">return this</span>; }<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">public</span> Order build(){ <span class=\"seg2\">return new</span> Order(<span class=\"seg2\">this</span>); }<br>\n&nbsp;&nbsp;}<br>\n}<br>\n<br>\n<span class=\"dim\">// 사용 — 순서 무관, 읽기 쉬움</span><br>\n<span class=\"seg2\">var</span> order = <span class=\"seg2\">new</span> Order.Builder().id(<span class=\"seg\">\"A1\"</span>).qty(<span class=\"seg\">5</span>).build();\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">실무 팁</span>\n<p>빌더를 손으로 다 짜는 건 보일러플레이트입니다. 실무에선 Lombok의 <code>@Builder</code>/<code>@Value</code> 애너테이션으로 자동 생성하거나, 단순 DTO는 <code>record</code>로 끝내는 경우가 많습니다. record는 빌더가 필요 없을 만큼 필드가 적을 때, 빌더는 선택 필드가 많을 때.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"java-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-06</span><h2>예외 처리</h2></div>\n<p class=\"lede\">Java 예외는 두 갈래 — <em>checked</em>(컴파일러가 처리를 강제)와 <em>unchecked</em>(런타임, 강제 안 함). JS에는 이 구분이 없어서 처음엔 낯섭니다.</p>\n<table>\n<tr><th>구분</th><th>예시 / 처리</th></tr>\n<tr><td><b>checked</b></td><td><code>IOException</code>, <code>SQLException</code> — <code>try-catch</code> 또는 <code>throws</code>로 선언 강제</td></tr>\n<tr><td><b>unchecked</b></td><td><code>NullPointerException</code>, <code>IllegalArgumentException</code> — 처리 강제 없음(보통 버그)</td></tr>\n</table>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">try-with-resources — 자동 close</span><br>\n<span class=\"dim\">// 괄호 안 자원은 끝나면 자동 close (JS엔 없는 패턴)</span><br>\n<span class=\"seg2\">try</span> (<span class=\"seg2\">var</span> reader = Files.newBufferedReader(path)) {<br>\n&nbsp;&nbsp;<span class=\"seg2\">return</span> reader.readLine();<br>\n} <span class=\"seg2\">catch</span> (IOException e) {<br>\n&nbsp;&nbsp;<span class=\"dim\">// expected failure — 회복 가능한 곳에서 처리</span><br>\n&nbsp;&nbsp;log.error(<span class=\"seg\">\"파일 읽기 실패: \"</span> + path, e);<br>\n&nbsp;&nbsp;<span class=\"seg2\">throw new</span> ConfigLoadException(<span class=\"seg\">\"설정 로드 실패\"</span>, e);<br>\n}\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">커스텀 예외 클래스</span><br>\n<span class=\"dim\">// RuntimeException 상속 = unchecked (요즘 도메인 예외 관례)</span><br>\n<span class=\"seg2\">public class</span> CreditNotFoundException <span class=\"seg2\">extends</span> RuntimeException {<br>\n&nbsp;&nbsp;<span class=\"seg2\">public</span> CreditNotFoundException(String id) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">super</span>(<span class=\"seg\">\"크레딧 없음: \"</span> + id);  <span class=\"dim\">// 메시지를 부모로</span><br>\n&nbsp;&nbsp;}<br>\n}<br>\n<br>\n<span class=\"dim\">// 던지기</span><br>\n<span class=\"seg2\">if</span> (credit == <span class=\"seg2\">null</span>) <span class=\"seg2\">throw new</span> CreditNotFoundException(id);\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">예외를 삼키지 마라</span>\n<p>빈 <code>catch {}</code>는 버그를 숨기는 최악의 패턴입니다. 잡았으면 ① 회복하거나 ② 로그를 남기고 의미 있는 예외로 다시 던지세요(<code>throw new ...(msg, e)</code> — 원인 <code>e</code>를 꼭 전달해 stack trace 보존). 회복 못 할 거면 애초에 잡지 말고 위로 흘려보내는 게 낫습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"java-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-07</span><h2>제네릭</h2></div>\n<p class=\"lede\">TS의 <code>&lt;T&gt;</code>와 같은 개념 — 타입을 파라미터로 받아 재사용 가능한 코드를 만듭니다. 차이: Java 제네릭은 컴파일 후 타입 정보가 지워집니다(type erasure).</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">제네릭 메서드 &amp; 클래스</span><br>\n<span class=\"dim\">// 제네릭 메서드 — &lt;T&gt;를 리턴 타입 앞에</span><br>\n<span class=\"seg2\">public static</span> &lt;T&gt; T firstOrNull(List&lt;T&gt; list) {<br>\n&nbsp;&nbsp;<span class=\"seg2\">return</span> list.isEmpty() ? <span class=\"seg2\">null</span> : list.get(<span class=\"seg\">0</span>);<br>\n}<br>\n<br>\n<span class=\"dim\">// 제네릭 클래스 — 결과 래퍼 같은 것</span><br>\n<span class=\"seg2\">public class</span> ApiResult&lt;T&gt; {<br>\n&nbsp;&nbsp;<span class=\"seg2\">private final</span> T data;<br>\n&nbsp;&nbsp;<span class=\"seg2\">private final</span> String error;<br>\n&nbsp;&nbsp;<span class=\"seg2\">public</span> ApiResult(T data, String error) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">this</span>.data = data; <span class=\"seg2\">this</span>.error = error;<br>\n&nbsp;&nbsp;}<br>\n&nbsp;&nbsp;<span class=\"seg2\">public</span> T data() { <span class=\"seg2\">return</span> data; }<br>\n}<br>\n<br>\nApiResult&lt;User&gt; res = <span class=\"seg2\">new</span> ApiResult&lt;&gt;(user, <span class=\"seg2\">null</span>);\n</div>\n<h3><span class=\"h3-tag\">7.1</span>와일드카드 ? extends</h3>\n<p>\"User든 그 하위 타입이든 다 받겠다\"를 표현 — 읽기 전용으로 여러 하위 타입을 함께 다룰 때 씁니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">WILDCARD</span><br>\n<span class=\"dim\">// ? extends Number — Number의 하위 타입 리스트 모두 허용</span><br>\n<span class=\"seg2\">public</span> <span class=\"seg2\">double</span> sum(List&lt;? <span class=\"seg2\">extends</span> Number&gt; nums) {<br>\n&nbsp;&nbsp;<span class=\"seg2\">double</span> total = <span class=\"seg\">0</span>;<br>\n&nbsp;&nbsp;<span class=\"seg2\">for</span> (Number n : nums) total += n.doubleValue();<br>\n&nbsp;&nbsp;<span class=\"seg2\">return</span> total;<br>\n}<br>\n<br>\n<span class=\"dim\">// 둘 다 호출 가능</span><br>\nsum(List.of(<span class=\"seg\">1</span>, <span class=\"seg\">2</span>, <span class=\"seg\">3</span>));          <span class=\"dim\">// List&lt;Integer&gt;</span><br>\nsum(List.of(<span class=\"seg\">1.5</span>, <span class=\"seg\">2.5</span>));          <span class=\"dim\">// List&lt;Double&gt;</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">PECS 기억법</span>\n<p>\"Producer Extends, Consumer Super\" — 값을 <em>꺼내 읽기만</em> 하면 <code>? extends T</code>, 값을 <em>넣기만</em> 하면 <code>? super T</code>. foundational 단계에선 <code>? extends</code>(읽기) 하나만 확실히 알아도 충분합니다. erasure 때문에 런타임에 <code>List&lt;String&gt;</code>인지 <code>List&lt;Integer&gt;</code>인지 구분 못 한다는 것만 기억하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"java-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-08</span><h2>동시성 기초</h2></div>\n<p class=\"lede\">JS는 단일 스레드 + 이벤트 루프지만, Java는 진짜 멀티스레드입니다. 스레드를 직접 만들기보다 <code>ExecutorService</code>(스레드 풀)와 <code>CompletableFuture</code>(JS Promise에 해당)를 씁니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">ExecutorService — 스레드 풀</span><br>\n<span class=\"seg2\">var</span> pool = Executors.newFixedThreadPool(<span class=\"seg\">4</span>);<br>\n<br>\n<span class=\"dim\">// 작업 제출 → Future로 결과 받기</span><br>\nFuture&lt;Integer&gt; future = pool.submit(() -&gt; heavyCompute());<br>\nInteger result = future.get();  <span class=\"dim\">// 끝날 때까지 블로킹</span><br>\n<br>\npool.shutdown();  <span class=\"dim\">// 반드시 종료 (안 하면 JVM 안 끝남)</span>\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">CompletableFuture — JS Promise 대응</span><br>\n<span class=\"dim\">// supplyAsync = Promise 시작, thenApply = .then()</span><br>\nCompletableFuture&lt;String&gt; cf = CompletableFuture<br>\n&nbsp;&nbsp;.supplyAsync(() -&gt; fetchUser(id))      <span class=\"dim\">// 비동기 실행</span><br>\n&nbsp;&nbsp;.thenApply(user -&gt; user.name())       <span class=\"dim\">// .then(u =&gt; u.name)</span><br>\n&nbsp;&nbsp;.thenApply(String::toUpperCase)<br>\n&nbsp;&nbsp;.exceptionally(e -&gt; <span class=\"seg\">\"기본값\"</span>);      <span class=\"dim\">// .catch()</span><br>\n<br>\nString name = cf.join();  <span class=\"dim\">// 결과 대기 (await 비슷)</span><br>\n<br>\n<span class=\"dim\">// 둘을 합치기 — Promise.all 비슷</span><br>\nCompletableFuture&lt;String&gt; combined = cf1<br>\n&nbsp;&nbsp;.thenCombine(cf2, (a, b) -&gt; a + b);\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">JS와 다른 점</span>\n<p>JS의 <code>await</code>는 이벤트 루프에 양보하지만, Java <code>future.get()</code>/<code>join()</code>은 <em>실제로 스레드를 블로킹</em>합니다. 공유 상태를 여러 스레드가 동시에 건드리면 race condition이 생기니 — foundational 단계에선 가능하면 불변 객체를 넘기고, 공유 가변 상태를 피하세요. 스레드 풀은 <code>shutdown()</code> 누락이 단골 버그입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"java-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-09</span><h2>날짜·시간</h2></div>\n<p class=\"lede\">옛날 <code>Date</code>/<code>Calendar</code>는 잊으세요 — Java 8+의 <code>java.time</code>이 표준입니다. 모두 <strong>불변</strong>이라 JS의 가변 <code>Date</code>보다 안전합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">java.time — 핵심 타입</span><br>\nLocalDate today = LocalDate.now();              <span class=\"dim\">// 날짜만 2026-06-23</span><br>\nLocalDate d = LocalDate.of(<span class=\"seg\">2026</span>, <span class=\"seg\">6</span>, <span class=\"seg\">23</span>);<br>\nLocalDateTime now = LocalDateTime.now();        <span class=\"dim\">// 날짜+시간</span><br>\nInstant ts = Instant.now();                     <span class=\"dim\">// UTC 타임스탬프</span><br>\n<br>\n<span class=\"dim\">// 연산 — 불변이라 새 객체 반환</span><br>\nLocalDate next = today.plusDays(<span class=\"seg\">7</span>);<br>\nLocalDate prev = today.minusMonths(<span class=\"seg\">1</span>);<br>\n<span class=\"seg2\">boolean</span> before = d.isBefore(today);\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">Duration · Period · 포맷</span><br>\n<span class=\"dim\">// 두 시각 사이 간격</span><br>\nDuration dur = Duration.between(start, end);<br>\n<span class=\"seg2\">long</span> mins = dur.toMinutes();<br>\n<br>\n<span class=\"dim\">// 두 날짜 사이 일수</span><br>\n<span class=\"seg2\">long</span> days = ChronoUnit.DAYS.between(d1, d2);<br>\n<br>\n<span class=\"dim\">// 포맷팅 — JS의 toLocaleDateString 대응</span><br>\n<span class=\"seg2\">var</span> fmt = DateTimeFormatter.ofPattern(<span class=\"seg\">\"yyyy-MM-dd HH:mm\"</span>);<br>\nString text = now.format(fmt);<br>\n<br>\n<span class=\"dim\">// 파싱 — 문자열 → 날짜</span><br>\nLocalDate parsed = LocalDate.parse(<span class=\"seg\">\"2026-06-23\"</span>);\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">타임존</span>\n<p>저장·전송은 <code>Instant</code>(UTC)로, 사용자 표시할 때만 <code>ZonedDateTime</code>으로 타임존을 입히는 게 안전합니다 — <code>instant.atZone(ZoneId.of(\"Asia/Seoul\"))</code>. <code>LocalDateTime</code>은 타임존 정보가 없으니, \"한국 시각 그대로\" 같은 의미가 필요할 때만 쓰세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"java-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-10</span><h2>자주 쓰는 이디엄</h2></div>\n<p class=\"lede\">매일 마주치는 작은 패턴들. equals/hashCode, enum, switch 표현식, 문자열 처리 — 여기서 JS 습관과 가장 자주 충돌합니다.</p>\n<h3><span class=\"h3-tag\">10.1</span>equals / hashCode</h3>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">동등성 — == 아님</span><br>\n<span class=\"dim\">// JS: a === b 와 다름!  ==는 참조(주소) 비교</span><br>\nString a = <span class=\"seg2\">new</span> String(<span class=\"seg\">\"hi\"</span>);<br>\nString b = <span class=\"seg2\">new</span> String(<span class=\"seg\">\"hi\"</span>);<br>\na == b;        <span class=\"dim\">// false — 다른 객체</span><br>\na.equals(b);   <span class=\"dim\">// true  — 값 비교 (이걸 써야 함)</span><br>\n<br>\n<span class=\"dim\">// null 안전 비교</span><br>\nObjects.equals(a, b);   <span class=\"dim\">// a가 null이어도 NPE 안 남</span>\n</div>\n<h3><span class=\"h3-tag\">10.2</span>enum · switch 표현식</h3>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">ENUM &amp; SWITCH EXPRESSION (Java 14+)</span><br>\n<span class=\"seg2\">public enum</span> CreditStatus { ISSUED, TRADED, RETIRED }<br>\n<br>\n<span class=\"dim\">// switch가 값을 반환 — 화살표 문법, break 불필요</span><br>\nString label = <span class=\"seg2\">switch</span> (status) {<br>\n&nbsp;&nbsp;<span class=\"seg2\">case</span> ISSUED -&gt; <span class=\"seg\">\"발행됨\"</span>;<br>\n&nbsp;&nbsp;<span class=\"seg2\">case</span> TRADED -&gt; <span class=\"seg\">\"거래됨\"</span>;<br>\n&nbsp;&nbsp;<span class=\"seg2\">case</span> RETIRED -&gt; <span class=\"seg\">\"소멸됨\"</span>;<br>\n};  <span class=\"dim\">// 모든 case 처리 안 하면 컴파일 에러 (안전)</span>\n</div>\n<h3><span class=\"h3-tag\">10.3</span>문자열 처리</h3>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">STRING</span><br>\nString.join(<span class=\"seg\">\", \"</span>, list);          <span class=\"dim\">// JS arr.join(\", \")</span><br>\n<span class=\"seg\">\"a,b,c\"</span>.split(<span class=\"seg\">\",\"</span>);              <span class=\"dim\">// → String[]</span><br>\n<span class=\"seg\">\"  hi  \"</span>.trim();                  <span class=\"dim\">// \"hi\"</span><br>\n<span class=\"seg\">\"Hello\"</span>.contains(<span class=\"seg\">\"ell\"</span>);        <span class=\"dim\">// true</span><br>\nString.format(<span class=\"seg\">\"%s = %d\"</span>, k, v);  <span class=\"dim\">// JS 템플릿 리터럴 대응</span><br>\n<br>\n<span class=\"dim\">// 여러 줄 — text block (Java 15+)</span><br>\nString json = <span class=\"seg\">\"\"\"</span><br>\n<span class=\"seg\">&nbsp;&nbsp;&nbsp;&nbsp;{ \"name\": \"haeun\" }</span><br>\n<span class=\"seg\">&nbsp;&nbsp;&nbsp;&nbsp;\"\"\"</span>;\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">== 함정</span>\n<p>JS 출신이 가장 많이 당하는 버그 — Java에서 객체 비교는 <strong>항상 <code>.equals()</code></strong>, <code>==</code>는 참조 비교입니다. 특히 <code>String</code>, <code>Integer</code>를 <code>==</code>로 비교하면 값이 같아도 <code>false</code>가 나올 수 있습니다(literal 캐싱 때문에 가끔 우연히 맞기도 해서 더 위험). 직접 만든 클래스를 <code>HashMap</code> 키나 <code>Set</code>에 넣으려면 <code>equals</code>+<code>hashCode</code>를 같이 구현해야 합니다(record는 자동).</p>\n</div>\n</section>\n\n<!-- ============ CH 11 ============ -->\n<section id=\"java-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">JAVA-11</span><h2>치트시트 — 복붙용 패턴</h2></div>\n<p class=\"lede\">반복해서 찾게 되는 한 줄들. 외우기보다 \"이렇게 쓴다\"를 눈에 익혀두고 필요할 때 가져다 고치세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>수정 가능 리스트</b><span>new ArrayList</span></div><div class=\"g-def\"><code>List&lt;String&gt; xs = new ArrayList&lt;&gt;();</code> — 이후 <code>xs.add(...)</code> 가능</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>불변 리스트/맵</b><span>List.of / Map.of</span></div><div class=\"g-def\"><code>List.of(\"a\",\"b\")</code> · <code>Map.of(\"k\", 1)</code> — 수정 시 예외</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>필터 + 변환 + 수집</b><span>stream chain</span></div><div class=\"g-def\"><code>xs.stream().filter(x -&gt; x &gt; 0).map(Obj::name).toList()</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>그룹핑</b><span>groupingBy</span></div><div class=\"g-def\"><code>xs.stream().collect(Collectors.groupingBy(X::city))</code> → <code>Map&lt;K, List&lt;X&gt;&gt;</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>합계</b><span>mapToInt.sum</span></div><div class=\"g-def\"><code>xs.stream().mapToInt(X::age).sum()</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>없으면 기본값</b><span>Optional.orElse</span></div><div class=\"g-def\"><code>opt.orElse(def)</code> · 없으면 예외 <code>opt.orElseThrow(() -&gt; new ...())</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>null 안전 체이닝</b><span>Optional.map</span></div><div class=\"g-def\"><code>opt.map(X::a).map(A::b).orElse(null)</code> — JS <code>?.</code> 대응</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>데이터 객체</b><span>record</span></div><div class=\"g-def\"><code>public record User(String name, int age) {}</code> — getter는 <code>u.name()</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>자원 자동 닫기</b><span>try-with-resources</span></div><div class=\"g-def\"><code>try (var r = open()) { ... } catch (IOException e) { ... }</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>값 비교</b><span>equals</span></div><div class=\"g-def\"><code>a.equals(b)</code> (== 아님) · null 안전은 <code>Objects.equals(a, b)</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>switch 표현식</b><span>switch -&gt;</span></div><div class=\"g-def\"><code>var r = switch(x) { case A -&gt; 1; default -&gt; 0; };</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>비동기 체이닝</b><span>CompletableFuture</span></div><div class=\"g-def\"><code>CompletableFuture.supplyAsync(() -&gt; f()).thenApply(g)</code> — JS Promise</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>오늘 + N일</b><span>java.time</span></div><div class=\"g-def\"><code>LocalDate.now().plusDays(7)</code> — 불변, 새 객체 반환</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>날짜 포맷</b><span>DateTimeFormatter</span></div><div class=\"g-def\"><code>now.format(DateTimeFormatter.ofPattern(\"yyyy-MM-dd\"))</code></div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>JS/TS 경험을 지렛대로 쓰세요 — 먼저 손에 붙일 것: <code>List/Map</code> 생성 · Stream 체이닝(<code>filter/map/toList</code>) · <code>Optional</code> · <code>record</code>. 이 넷이 일상 코드의 대부분입니다. 그다음 예외(checked/unchecked)와 <code>equals</code> vs <code>==</code> 함정을 잡으면 NPE·버그가 크게 줄어듭니다. 동시성과 와일드카드는 필요해질 때 이 문서로 돌아오면 됩니다.</p>\n</div>\n</section>\n\n<footer>\nJAVA EXAMPLES · V1 · 2026-06<br>\nSTACK : JAVA 17+ · 모든 코드는 Java 17 기준 문법 (var · record · switch expression · text block)<br>\nNOTE : JS/TS 대비 지점은 본문 표기 · COMPANION : BACKEND ENGINEERING HANDBOOK\n</footer>\n\n<section id=\"doc-jpa\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>JPA 예시</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : JPA-EXAMPLES-V1</span>\n    <span>STACK : SPRING DATA JPA · HIBERNATE</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>JPA<br>예시 사례</h1>\n  <p class=\"hero-sub\">엔티티 매핑부터 N+1 회피까지 — 바로 복붙해 쓰는 JPA 레시피. 개념의 <strong>왜</strong>는 JPA 핸드북에 넘기고, 여기선 <strong>실제로 어떻게 쓰는지</strong>만 코드로 봅니다. 각 섹션은 \"언제·왜\" 한두 줄 + 복붙 가능한 코드 + 발 걸리는 곳 경고.</p>\n  <div class=\"hero-meta\">NOTE : 패키지는 jakarta.persistence.* (Spring Boot 3 / Jakarta EE 9+) 기준 — 구버전은 javax.persistence.*<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"jpa-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-01</span><h2>엔티티 기본</h2></div>\n<p class=\"lede\">테이블 하나를 객체 하나에 매핑하는 출발점. <em>엔티티 = DB 테이블에 대응하는 영속 객체</em>이고, JPA가 추적할 수 있는 형태로 만드는 게 1번 작업입니다.</p>\n<pre class=\"snippet-card\">\n<span class=\"sc-label\">Member.java — 가장 기본형 엔티티</span>\n<span class=\"seg2\">@Entity</span><br>\n<span class=\"seg2\">@Table</span>(name = <span class=\"seg\">\"member\"</span>)<br>\n<span class=\"dim\">public class</span> Member {<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Id</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@GeneratedValue</span>(strategy = GenerationType.<span class=\"seg\">IDENTITY</span>)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> Long id;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Column</span>(name = <span class=\"seg\">\"email\"</span>, nullable = <span class=\"seg\">false</span>, unique = <span class=\"seg\">true</span>, length = 100)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> String email;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Column</span>(nullable = <span class=\"seg\">false</span>)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> String name;<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">protected</span> Member() {}&nbsp;&nbsp;<span class=\"dim\">// JPA 기본 생성자 (필수)</span><br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">public</span> Member(String email, String name) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\">this</span>.email = email;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\">this</span>.name = name;<br>\n&nbsp;&nbsp;}<br>\n&nbsp;&nbsp;<span class=\"dim\">// getter ...</span><br>\n}\n</pre>\n<table>\n<tr><th>어노테이션</th><th>역할</th></tr>\n<tr><td><code>@Entity</code></td><td>이 클래스를 영속 엔티티로 등록. 클래스명이 기본 엔티티명</td></tr>\n<tr><td><code>@Table(name=...)</code></td><td>매핑할 테이블명 지정. 생략하면 엔티티명을 테이블명으로</td></tr>\n<tr><td><code>@Id</code></td><td>PK 필드 표시 (엔티티당 하나는 필수)</td></tr>\n<tr><td><code>@GeneratedValue(strategy=IDENTITY)</code></td><td>PK를 DB의 AUTO_INCREMENT에 위임 (MySQL·PostgreSQL 흔함)</td></tr>\n<tr><td><code>@Column(nullable, unique, length)</code></td><td>컬럼 제약. 생략하면 필드명·기본 제약으로 매핑</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">기본 생성자는 빼먹지 말 것</span>\n<p>JPA는 reflection으로 엔티티를 만들기 때문에 <strong>파라미터 없는 기본 생성자</strong>가 반드시 있어야 합니다. 접근 제어는 <code>protected</code>까지 허용 — 외부에서 빈 객체를 못 만들게 막으면서 JPA·프록시는 쓸 수 있습니다. <code>final</code> 클래스/필드, <code>@Id</code> 없는 엔티티는 안 됩니다. (→ JPA 핸드북: 엔티티 생명주기)</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"jpa-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-02</span><h2>연관관계 매핑</h2></div>\n<p class=\"lede\">테이블의 외래키(FK)를 객체 참조로 바꾸는 작업. 핵심 두 가지 — <em>FK를 가진 쪽이 연관관계의 주인(owner)</em>이고, fetch는 거의 항상 <code>LAZY</code>로 시작합니다.</p>\n<pre class=\"snippet-card\">\n<span class=\"sc-label\">N:1 — 주인 쪽 (FK 보유: Order → Member)</span>\n<span class=\"seg2\">@Entity</span><br>\n<span class=\"dim\">public class</span> Order {<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Id</span> <span class=\"seg2\">@GeneratedValue</span>(strategy = GenerationType.<span class=\"seg\">IDENTITY</span>)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> Long id;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@ManyToOne</span>(fetch = FetchType.<span class=\"seg\">LAZY</span>)<br>\n&nbsp;&nbsp;<span class=\"seg2\">@JoinColumn</span>(name = <span class=\"seg\">\"member_id\"</span>)&nbsp;&nbsp;<span class=\"dim\">// FK 컬럼명</span><br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> Member member;<br>\n}\n</pre>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">1:N — 반대편 (mappedBy: 거울만, FK 없음)</span><br>\n<span class=\"seg2\">@Entity</span><br>\n<span class=\"dim\">public class</span> Member {<br>\n&nbsp;&nbsp;<span class=\"dim\">// ... @Id 등</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@OneToMany</span>(mappedBy = <span class=\"seg\">\"member\"</span>, cascade = CascadeType.<span class=\"seg\">ALL</span>, orphanRemoval = <span class=\"seg\">true</span>)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> List&lt;Order&gt; orders = <span class=\"dim\">new</span> ArrayList&lt;&gt;();<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// 양방향 연관관계 편의 메서드</span><br>\n&nbsp;&nbsp;<span class=\"dim\">public void</span> addOrder(Order order) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\">this</span>.orders.add(order);<br>\n&nbsp;&nbsp;&nbsp;&nbsp;order.setMember(<span class=\"dim\">this</span>);&nbsp;&nbsp;<span class=\"dim\">// 양쪽 동기화</span><br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<table>\n<tr><th>요소</th><th>의미</th></tr>\n<tr><td><code>@ManyToOne</code> + <code>@JoinColumn</code></td><td>FK를 가진 <em>주인</em> 쪽. <code>name</code>이 실제 FK 컬럼명</td></tr>\n<tr><td><code>@OneToMany(mappedBy=\"member\")</code></td><td>주인이 아닌 거울. <code>mappedBy</code>는 <em>상대 엔티티의 필드명</em></td></tr>\n<tr><td><code>cascade = ALL</code></td><td>부모 영속화/삭제가 자식에 전파 (수명주기 종속일 때만)</td></tr>\n<tr><td><code>orphanRemoval = true</code></td><td>컬렉션에서 빠진 자식을 DELETE</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">편의 메서드를 쓰는 이유</span>\n<p>양방향에선 <strong>객체 양쪽을 직접 맞춰줘야</strong> 합니다 — JPA가 자동으로 동기화하지 않습니다. <code>order.setMember(member)</code>만 하고 <code>member.getOrders()</code>에 안 넣으면, 같은 트랜잭션 안에서 컬렉션이 비어 보이는 버그가 납니다. 그래서 한쪽에 <code>addOrder</code> 같은 편의 메서드를 두고 양쪽을 한 번에 맞춥니다. DB에 FK를 쓰는 건 <em>주인 쪽(<code>@ManyToOne</code>)</em>뿐이라는 점도 기억하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"jpa-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-03</span><h2>Repository</h2></div>\n<p class=\"lede\">Spring Data JPA의 핵심 편의 — <em>인터페이스만 선언하면 구현체는 런타임에 자동 생성</em>됩니다. 메서드 이름 규칙만 지키면 쿼리가 만들어집니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">MemberRepository.java — 쿼리 메서드</span><br>\n<span class=\"dim\">public interface</span> MemberRepository <span class=\"dim\">extends</span> JpaRepository&lt;Member, Long&gt; {<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// SELECT ... WHERE email = ?</span><br>\n&nbsp;&nbsp;Optional&lt;Member&gt; <span class=\"seg\">findByEmail</span>(String email);<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// SELECT ... WHERE name LIKE %?%</span><br>\n&nbsp;&nbsp;List&lt;Member&gt; <span class=\"seg\">findByNameContaining</span>(String keyword);<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// SELECT EXISTS ... WHERE email = ?</span><br>\n&nbsp;&nbsp;<span class=\"dim\">boolean</span> <span class=\"seg\">existsByEmail</span>(String email);<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// SELECT COUNT(*) WHERE name = ?</span><br>\n&nbsp;&nbsp;<span class=\"dim\">long</span> <span class=\"seg\">countByName</span>(String name);<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// 조건 조합 — AND / OrderBy</span><br>\n&nbsp;&nbsp;List&lt;Member&gt; <span class=\"seg\">findByNameAndEmail</span>(String name, String email);<br>\n&nbsp;&nbsp;List&lt;Member&gt; <span class=\"seg\">findByNameOrderByIdDesc</span>(String name);<br>\n}\n</div>\n<table>\n<tr><th>키워드</th><th>생성되는 조건</th></tr>\n<tr><td><code>findBy필드</code></td><td><code>WHERE 필드 = ?</code> — 단건은 <code>Optional&lt;T&gt;</code>, 다건은 <code>List&lt;T&gt;</code></td></tr>\n<tr><td><code>Containing</code> / <code>StartingWith</code></td><td><code>LIKE %?%</code> / <code>LIKE ?%</code></td></tr>\n<tr><td><code>existsBy필드</code></td><td><code>boolean</code> 반환 — 존재 여부만 (count보다 가벼움)</td></tr>\n<tr><td><code>countBy필드</code></td><td><code>long</code> 반환 — 개수</td></tr>\n<tr><td><code>And</code> / <code>Or</code> / <code>OrderBy</code></td><td>조건 조합·정렬</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">JpaRepository가 공짜로 주는 것</span>\n<p><code>JpaRepository&lt;Member, Long&gt;</code>만 상속해도 <code>save</code>, <code>findById</code>, <code>findAll</code>, <code>delete</code>, <code>count</code> 등이 이미 들어 있습니다. 제네릭은 <code>&lt;엔티티타입, PK타입&gt;</code> 순서. 단건 조회는 <code>null</code> 대신 <code>Optional</code>로 받아 <code>orElseThrow</code>로 명시적으로 처리하는 패턴을 권합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"jpa-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-04</span><h2>JPQL과 @Query</h2></div>\n<p class=\"lede\">메서드 이름으로 표현이 안 되는 쿼리는 직접 씁니다. <em>JPQL은 테이블이 아니라 엔티티·필드를 대상으로 하는 쿼리</em>입니다 — <code>FROM Member m</code>처럼 클래스명을 씁니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">@Query — JPQL + @Param 바인딩</span><br>\n<span class=\"seg2\">@Query</span>(<span class=\"seg\">\"SELECT m FROM Member m WHERE m.email = :email\"</span>)<br>\nOptional&lt;Member&gt; findByEmailJpql(<span class=\"seg2\">@Param</span>(<span class=\"seg\">\"email\"</span>) String email);<br>\n<br>\n<span class=\"dim\">// 일부 컬럼만 — DTO projection (생성자 표현식)</span><br>\n<span class=\"seg2\">@Query</span>(<span class=\"seg\">\"SELECT new com.example.dto.MemberView(m.id, m.name) FROM Member m\"</span>)<br>\nList&lt;MemberView&gt; findAllViews();<br>\n<br>\n<span class=\"dim\">// 네이티브 SQL — DB 함수가 필요할 때</span><br>\n<span class=\"seg2\">@Query</span>(value = <span class=\"seg\">\"SELECT * FROM member WHERE email = :email\"</span>, nativeQuery = <span class=\"seg\">true</span>)<br>\nOptional&lt;Member&gt; findByEmailNative(<span class=\"seg2\">@Param</span>(<span class=\"seg\">\"email\"</span>) String email);\n</div>\n<table>\n<tr><th>방식</th><th>언제</th></tr>\n<tr><td>JPQL <code>@Query</code></td><td>기본. 엔티티·필드 기준, DB 독립적</td></tr>\n<tr><td><code>@Param</code> 바인딩</td><td><code>:name</code> 형태 이름 파라미터. SQL 인젝션 방지에도 필수</td></tr>\n<tr><td>DTO projection</td><td><code>SELECT new ...</code>로 필요한 컬럼만 — 조회 전용에 유리</td></tr>\n<tr><td><code>nativeQuery = true</code></td><td>DB 고유 함수·복잡 SQL이 필요할 때만. 이식성 포기</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">문자열 연결로 파라미터 넣지 말 것</span>\n<p><code>\"WHERE email = '\" + email + \"'\"</code> 같은 문자열 조립은 <strong>SQL 인젝션</strong>입니다. 항상 <code>:param</code> + <code>@Param</code> 바인딩을 쓰세요 — JPA가 parameterized query로 처리합니다. 네이티브 쿼리도 마찬가지로 바인딩으로만 값을 넣습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"jpa-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-05</span><h2>N+1 해결</h2></div>\n<p class=\"lede\">JPA에서 가장 자주 만나는 성능 함정. <em>목록 1번 조회 후, 각 행의 연관 엔티티를 N번 추가 조회</em>하는 현상입니다. LAZY 연관을 루프에서 건드릴 때 터집니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">문제 재현 — orders 10건이면 쿼리 1 + 10 = 11번</span><br>\nList&lt;Order&gt; orders = orderRepository.findAll();&nbsp;&nbsp;<span class=\"dim\">// SELECT * FROM orders (1번)</span><br>\n<span class=\"dim\">for</span> (Order o : orders) {<br>\n&nbsp;&nbsp;o.getMember().getName();&nbsp;&nbsp;<span class=\"dim\">// member마다 SELECT (N번) ← 문제</span><br>\n}\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">해결 1 — fetch join (한 방에 조인 조회)</span><br>\n<span class=\"seg2\">@Query</span>(<span class=\"seg\">\"SELECT o FROM Order o JOIN FETCH o.member\"</span>)<br>\nList&lt;Order&gt; findAllWithMember();<br>\n<br>\n<span class=\"sc-label\">해결 2 — @EntityGraph (메서드 이름 규칙 유지하며 fetch)</span><br>\n<span class=\"seg2\">@EntityGraph</span>(attributePaths = {<span class=\"seg\">\"member\"</span>})<br>\n<span class=\"seg2\">@Query</span>(<span class=\"seg\">\"SELECT o FROM Order o\"</span>)<br>\nList&lt;Order&gt; findAllGraph();\n</div>\n<table>\n<tr><th>해결책</th><th>특징</th></tr>\n<tr><td>fetch join <code>JOIN FETCH</code></td><td>가장 명시적. <code>@ManyToOne</code>·단건 컬렉션에 적합</td></tr>\n<tr><td><code>@EntityGraph(attributePaths)</code></td><td>JPQL 없이 어노테이션으로 fetch 지정. 쿼리 메서드와 조합 가능</td></tr>\n<tr><td><code>default_batch_fetch_size</code></td><td>컬렉션 N+1을 <code>IN (?, ?, ...)</code>로 묶어 N → 1~몇 번으로</td></tr>\n</table>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">해결 3 — 컬렉션엔 batch size (application.yml)</span><br>\nspring:<br>\n&nbsp;&nbsp;jpa:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;properties:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;hibernate:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">default_batch_fetch_size</span>: <span class=\"seg\">100</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">컬렉션 fetch join + 페이징은 함께 못 씀</span>\n<p><code>@OneToMany</code> 컬렉션에 <code>JOIN FETCH</code>와 <code>Pageable</code>을 같이 쓰면, Hibernate가 <em>메모리에서 페이징</em>하며 경고를 띄웁니다(전체를 다 읽음). 컬렉션 N+1은 fetch join 대신 <code>default_batch_fetch_size</code>로 푸는 게 정석입니다. <code>@ManyToOne</code>·<code>@OneToOne</code>(to-one) 연관은 fetch join + 페이징이 안전합니다. (→ JPA 핸드북: N+1 심화)</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"jpa-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-06</span><h2>페이징·정렬</h2></div>\n<p class=\"lede\">목록을 통째로 읽지 말고 페이지 단위로. Spring Data가 <code>Pageable</code> 하나로 <em>LIMIT·OFFSET·정렬·전체 개수</em>를 한 번에 처리합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">Repository — Pageable 파라미터만 추가</span><br>\nPage&lt;Member&gt; findByNameContaining(String keyword, Pageable pageable);<br>\n<br>\n<span class=\"sc-label\">호출 — PageRequest.of(page, size, sort)</span><br>\nPageable pageable = PageRequest.<span class=\"seg\">of</span>(0, 20, Sort.by(Sort.Direction.<span class=\"seg\">DESC</span>, <span class=\"seg\">\"id\"</span>));<br>\nPage&lt;Member&gt; page = memberRepository.findByNameContaining(<span class=\"seg\">\"kim\"</span>, pageable);<br>\n<br>\nList&lt;Member&gt; content = page.getContent();&nbsp;&nbsp;<span class=\"dim\">// 현재 페이지 데이터</span><br>\n<span class=\"dim\">long</span> total = page.getTotalElements();&nbsp;&nbsp;<span class=\"dim\">// 전체 개수 (count 쿼리 자동)</span><br>\n<span class=\"dim\">int</span> pages = page.getTotalPages();&nbsp;&nbsp;<span class=\"dim\">boolean</span> last = page.isLast();\n</div>\n<table>\n<tr><th>요소</th><th>의미</th></tr>\n<tr><td><code>Pageable</code></td><td>페이지 번호·크기·정렬을 담는 요청 객체</td></tr>\n<tr><td><code>PageRequest.of(page, size)</code></td><td>0-based 페이지 번호. <code>of(0, 20)</code>은 첫 20개</td></tr>\n<tr><td><code>Page&lt;T&gt;</code></td><td>데이터 + 전체 개수 + 페이지 메타. count 쿼리가 같이 나감</td></tr>\n<tr><td><code>Slice&lt;T&gt;</code></td><td>전체 개수 불필요할 때 (count 쿼리 생략, \"더보기\"식)</td></tr>\n<tr><td><code>Sort.by(...)</code></td><td>정렬. <code>PageRequest.of(p, s, sort)</code>로 합쳐 전달</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">page는 0부터</span>\n<p><code>PageRequest.of</code>의 페이지 번호는 <strong>0-based</strong>입니다 — 첫 페이지가 <code>0</code>. 프론트의 1-based 페이지와 어긋나기 쉬우니 변환을 한 곳에서 처리하세요. 전체 개수가 굳이 필요 없는 무한 스크롤은 <code>Page</code> 대신 <code>Slice</code>를 쓰면 count 쿼리를 아낍니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"jpa-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-07</span><h2>트랜잭션·영속성 컨텍스트</h2></div>\n<p class=\"lede\">JPA의 마법이자 함정. <em>트랜잭션 안에서 조회한 엔티티는 영속 상태이고, 값을 바꾸면 커밋 시점에 자동으로 UPDATE가 나갑니다</em> — 이게 dirty checking입니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">변경감지 — save() 호출이 없어도 UPDATE</span><br>\n<span class=\"seg2\">@Transactional</span><br>\n<span class=\"dim\">public void</span> changeName(Long id, String newName) {<br>\n&nbsp;&nbsp;Member member = memberRepository.findById(id)<br>\n&nbsp;&nbsp;&nbsp;&nbsp;.orElseThrow(() -&gt; <span class=\"dim\">new</span> IllegalArgumentException(<span class=\"seg\">\"없는 회원\"</span>));<br>\n<br>\n&nbsp;&nbsp;member.changeName(newName);&nbsp;&nbsp;<span class=\"dim\">// 필드만 변경</span><br>\n&nbsp;&nbsp;<span class=\"dim\">// save() 호출 불필요 — 커밋 시 dirty checking으로 UPDATE 자동</span><br>\n}\n</div>\n<table>\n<tr><th>상황</th><th>해야 할 일</th></tr>\n<tr><td>이미 영속 상태인 엔티티 수정</td><td><strong>변경감지</strong> — 필드만 바꾸면 끝. <code>save()</code> 불필요</td></tr>\n<tr><td>새 엔티티 저장 (PK 없음)</td><td><code>save()</code> 명시 호출 → INSERT</td></tr>\n<tr><td>준영속/분리된 엔티티 반영</td><td><code>save()</code>(merge) 호출 필요</td></tr>\n<tr><td>읽기 전용 메서드</td><td><code>@Transactional(readOnly = true)</code> — 스냅샷 생략, 최적화</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">변경감지는 트랜잭션 경계 안에서만</span>\n<p>dirty checking은 <strong>영속성 컨텍스트가 살아 있는 동안</strong>, 즉 <code>@Transactional</code> 경계 안에서만 동작합니다. 트랜잭션 밖에서 받은 엔티티는 준영속(detached) 상태라 필드를 바꿔도 DB에 반영되지 않습니다. 그래서 수정 로직은 트랜잭션 안의 서비스 메서드에 두고, 거기서 조회한 엔티티를 바꿔야 합니다. LAZY 연관 접근도 같은 이유로 트랜잭션 밖이면 <code>LazyInitializationException</code>이 납니다. (→ JPA 핸드북: 영속성 컨텍스트)</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"jpa-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-08</span><h2>낙관적 락</h2></div>\n<p class=\"lede\">두 트랜잭션이 같은 행을 동시에 수정할 때, <em>마지막 저장이 앞 저장을 덮어쓰는(lost update)</em> 문제를 막습니다. 락을 미리 걸지 않고 \"충돌하면 그때 실패\"시키는 방식.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">@Version 필드 하나면 끝</span><br>\n<span class=\"seg2\">@Entity</span><br>\n<span class=\"dim\">public class</span> Product {<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Id</span> <span class=\"seg2\">@GeneratedValue</span>(strategy = GenerationType.<span class=\"seg\">IDENTITY</span>)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> Long id;<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">private int</span> stock;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Version</span><br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> Long version;&nbsp;&nbsp;<span class=\"dim\">// UPDATE 때마다 자동 +1, WHERE version=? 로 충돌 검출</span><br>\n}\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">충돌 처리 — 예외 잡아 재시도/안내</span><br>\n<span class=\"seg2\">@Transactional</span><br>\n<span class=\"dim\">public void</span> decreaseStock(Long id, <span class=\"dim\">int</span> qty) {<br>\n&nbsp;&nbsp;Product p = productRepository.findById(id).orElseThrow();<br>\n&nbsp;&nbsp;p.decrease(qty);&nbsp;&nbsp;<span class=\"dim\">// 커밋 시 UPDATE ... SET version=version+1 WHERE id=? AND version=?</span><br>\n}<br>\n<span class=\"dim\">// 다른 트랜잭션이 먼저 바꿨다면 → OptimisticLockingFailureException</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">동작 원리와 한계</span>\n<p><code>@Version</code> 필드가 있으면 Hibernate가 UPDATE에 <code>WHERE id=? AND version=?</code>를 붙입니다. 그 사이 누가 먼저 수정했으면 version이 안 맞아 <em>영향받은 행 0건</em> → <code>OptimisticLockingFailureException</code>(JPA 표준은 <code>OptimisticLockException</code>). 충돌 빈도가 낮을 때 적합하고, 충돌 시 <strong>재시도하거나 사용자에게 다시 시도를 안내</strong>해야 합니다. 충돌이 잦으면 비관적 락(<code>@Lock(PESSIMISTIC_WRITE)</code>)을 검토하세요. (→ JPA 핸드북: 동시성 제어)</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"jpa-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-09</span><h2>Auditing</h2></div>\n<p class=\"lede\">생성·수정 시각을 매번 수동으로 세팅하지 마세요. <em>JPA Auditing이 INSERT·UPDATE 시점에 자동으로 채워줍니다</em>. 거의 모든 엔티티에 공통으로 들어가는 패턴.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">1) 설정 활성화 (@Configuration 또는 메인 클래스)</span><br>\n<span class=\"seg2\">@Configuration</span><br>\n<span class=\"seg2\">@EnableJpaAuditing</span><br>\n<span class=\"dim\">public class</span> JpaConfig {}\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">2) 공통 베이스 클래스 — 상속해서 재사용</span><br>\n<span class=\"seg2\">@MappedSuperclass</span><br>\n<span class=\"seg2\">@EntityListeners</span>(AuditingEntityListener.<span class=\"dim\">class</span>)<br>\n<span class=\"dim\">public abstract class</span> BaseTimeEntity {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@CreatedDate</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@Column</span>(updatable = <span class=\"seg\">false</span>)<br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> LocalDateTime createdAt;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@LastModifiedDate</span><br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> LocalDateTime updatedAt;<br>\n}<br>\n<br>\n<span class=\"dim\">// 사용: public class Member extends BaseTimeEntity { ... }</span>\n</div>\n<table>\n<tr><th>요소</th><th>역할</th></tr>\n<tr><td><code>@EnableJpaAuditing</code></td><td>Auditing 기능 켜기 (설정에 한 번)</td></tr>\n<tr><td><code>@EntityListeners(AuditingEntityListener.class)</code></td><td>해당 엔티티에 Auditing 리스너 연결</td></tr>\n<tr><td><code>@CreatedDate</code></td><td>INSERT 시각 자동 기록 (<code>updatable=false</code>로 고정)</td></tr>\n<tr><td><code>@LastModifiedDate</code></td><td>UPDATE 시각 자동 갱신</td></tr>\n<tr><td><code>@MappedSuperclass</code></td><td>테이블 없는 공통 매핑 부모 — 필드만 상속</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">생성자·수정자도 자동으로</span>\n<p>시각뿐 아니라 <em>누가</em> 만들고 바꿨는지도 <code>@CreatedBy</code>/<code>@LastModifiedBy</code>로 자동 기록할 수 있습니다 — <code>AuditorAware&lt;String&gt;</code> 빈을 등록해 현재 사용자를 공급하면 됩니다. 시간대는 <code>LocalDateTime</code>이 기본이지만, 다국가/UTC 저장이 필요하면 <code>Instant</code>를 검토하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"jpa-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-10</span><h2>치트시트 — 자주 쓰는 한 줄</h2></div>\n<p class=\"lede\">현장에서 반복되는 어노테이션·API. 외우기보다 \"이게 있다\"를 알아두고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>엔티티 선언</b><span>@Entity</span></div><div class=\"g-def\"><code>@Entity</code> + <code>@Id</code> + 기본 생성자(<code>protected</code>)는 최소 3종 세트. <code>@Table(name=...)</code>로 테이블명 지정</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>PK 자동 생성</b><span>@GeneratedValue</span></div><div class=\"g-def\"><code>@GeneratedValue(strategy = GenerationType.IDENTITY)</code> — DB AUTO_INCREMENT 위임. MySQL·PostgreSQL 기본 선택</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>N:1 (FK 주인)</b><span>@ManyToOne</span></div><div class=\"g-def\"><code>@ManyToOne(fetch = FetchType.LAZY)</code> + <code>@JoinColumn(name=\"member_id\")</code>. fetch는 항상 LAZY부터</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>1:N (거울)</b><span>@OneToMany</span></div><div class=\"g-def\"><code>@OneToMany(mappedBy=\"member\")</code> — <code>mappedBy</code>는 상대 엔티티의 필드명. 양방향 편의 메서드로 동기화</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Repository 상속</b><span>JpaRepository</span></div><div class=\"g-def\"><code>interface MemberRepository extends JpaRepository&lt;Member, Long&gt;</code> — <code>&lt;엔티티, PK타입&gt;</code> 순서</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>쿼리 메서드</b><span>findBy / existsBy / countBy</span></div><div class=\"g-def\"><code>findByEmail</code>, <code>findByNameContaining</code>, <code>existsByEmail</code>, <code>countByName</code> — 이름 규칙으로 쿼리 자동 생성</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>직접 쿼리</b><span>@Query + @Param</span></div><div class=\"g-def\"><code>@Query(\"SELECT m FROM Member m WHERE m.email = :email\")</code> + <code>@Param(\"email\")</code>. 네이티브는 <code>nativeQuery = true</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>N+1 (to-one)</b><span>fetch join</span></div><div class=\"g-def\"><code>@Query(\"SELECT o FROM Order o JOIN FETCH o.member\")</code> 또는 <code>@EntityGraph(attributePaths={\"member\"})</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>N+1 (컬렉션)</b><span>batch_fetch_size</span></div><div class=\"g-def\"><code>hibernate.default_batch_fetch_size: 100</code> — 컬렉션을 <code>IN (?,?,...)</code>으로 묶음. 페이징과 fetch join 동시 금지</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>페이징</b><span>Pageable / Page</span></div><div class=\"g-def\"><code>PageRequest.of(0, 20, Sort.by(\"id\"))</code> → <code>Page&lt;Member&gt;</code>. 페이지는 0-based, count 쿼리 자동</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>트랜잭션 경계</b><span>@Transactional</span></div><div class=\"g-def\">서비스 메서드에 부착. 안에서 조회한 엔티티는 필드만 바꿔도 <strong>변경감지(dirty checking)</strong>로 UPDATE 자동. 읽기는 <code>readOnly = true</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>동시 수정 충돌</b><span>@Version</span></div><div class=\"g-def\"><code>@Version</code> 필드 추가 → UPDATE에 <code>WHERE version=?</code>. 충돌 시 <code>OptimisticLockingFailureException</code> → 재시도/안내</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>시각 자동 기록</b><span>Auditing</span></div><div class=\"g-def\"><code>@EnableJpaAuditing</code> + <code>@EntityListeners(AuditingEntityListener.class)</code> + <code>@CreatedDate</code>/<code>@LastModifiedDate</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>공통 필드 상속</b><span>@MappedSuperclass</span></div><div class=\"g-def\"><code>@MappedSuperclass</code>로 베이스 클래스 만들어 createdAt/updatedAt 등 공통 필드를 모든 엔티티에 상속</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>전부 한 번에 외우려 하지 마세요. 손에 먼저 붙일 것: <code>@Entity</code>+<code>@Id</code> · <code>JpaRepository</code> 상속 · 쿼리 메서드(<code>findBy</code>) · <code>@Transactional</code> 안에서의 변경감지. 이 네 가지로 foundational CRUD는 끝납니다. 그다음 실무에서 거의 반드시 만나는 게 <strong>N+1</strong>(JPA-05)이니, 여기까지 잡으면 실전 80%입니다. 각 항목의 <em>왜</em>가 궁금하면 JPA 핸드북에서 영속성 컨텍스트·프록시·flush 타이밍을 보세요.</p>\n</div>\n</section>\n\n<section id=\"jpa-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">JPA-11</span><h2>프록시·flush·연관관계 심화</h2></div>\n<p class=\"lede\">JPA 면접에서 깊이를 가르는 지점은 어노테이션 이름이 아니라 “언제 SQL이 나가고, 언제 프록시가 초기화되고, 왜 트랜잭션 밖에서 터지는가”를 설명하는 능력입니다.</p>\n<table>\n<tr><th>개념</th><th>실제 의미</th><th>자주 터지는 문제</th></tr>\n<tr><td>Persistence Context</td><td>트랜잭션 동안 엔티티를 추적하는 1차 캐시와 변경 감지 공간</td><td>같은 id 조회는 같은 객체, 변경은 commit/flush 때 SQL로 반영</td></tr>\n<tr><td>Proxy</td><td>연관 엔티티를 실제 객체 대신 대리 객체로 들고 있다가 접근 시 로딩</td><td>트랜잭션 밖 접근 시 LazyInitializationException</td></tr>\n<tr><td>Flush</td><td>영속성 컨텍스트 변경을 DB SQL로 밀어내는 과정</td><td>commit 전 JPQL 실행 전에 자동 flush되어 예상보다 빨리 UPDATE 발생</td></tr>\n<tr><td>Dirty Checking</td><td>스냅샷과 현재 엔티티 값을 비교해 UPDATE 생성</td><td>setter 남용 시 의도치 않은 UPDATE, 변경 범위 추적 어려움</td></tr>\n<tr><td>Cascade</td><td>부모 엔티티 작업을 자식에게 전파</td><td>삭제 전파 범위 오해로 데이터 손실</td></tr>\n<tr><td>orphanRemoval</td><td>부모 컬렉션에서 빠진 자식을 삭제 대상으로 봄</td><td>단순 관계 해제가 실제 DELETE로 이어짐</td></tr>\n</table>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">FLUSH TIMING</span><br>\n1. transaction commit 직전<br>\n2. JPQL 실행 전, 쿼리 결과와 영속성 컨텍스트 변경을 맞추기 위해<br>\n3. entityManager.flush() 명시 호출<br>\n<span class=\"dim\">flush는 commit이 아니다. SQL은 DB에 보내지만 rollback되면 취소된다.</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">fetch join과 pagination</span>\n<p>to-one 연관은 fetch join으로 비교적 안전하게 함께 가져올 수 있습니다. 하지만 to-many 컬렉션 fetch join에 pagination을 섞으면 DB에서 페이지를 자르는 것이 아니라 메모리에서 잘리거나 row가 부풀어 결과가 왜곡될 수 있습니다. 컬렉션은 batch fetch size, 별도 조회, DTO projection을 고려해야 합니다.</p>\n</div>\n<h3>면접 답변 예시</h3>\n<div class=\"semantic-card answer-card\"><span class=\"sc-label\">JPA DEPTH ANSWER</span><br>JPA는 트랜잭션 안에서 영속성 컨텍스트가 엔티티를 추적하고, 변경 감지로 flush 시점에 SQL을 생성합니다. lazy 연관은 프록시로 들고 있다가 접근 시 로딩되므로 트랜잭션 밖에서는 LazyInitializationException이 날 수 있습니다. 그래서 조회 목적에 따라 fetch join, entity graph, batch fetch, DTO projection을 고르고, 특히 컬렉션 fetch join과 pagination은 조심합니다.</div>\n</section>\n\n<footer>\nJPA EXAMPLES · V1 · 2026-06<br>\nSTACK : SPRING DATA JPA · HIBERNATE · jakarta.persistence (Spring Boot 3+)<br>\nNOTE : 구버전 Spring Boot 2.x는 javax.persistence.* · COMPANION : JPA 핸드북(개념 심화)\n</footer>\n\n<section id=\"doc-spring\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Spring Boot 예시</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : SPRING-EXAMPLES-V1</span>\n    <span>STACK : SPRING BOOT 3.x</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>Spring Boot<br>예시 사례</h1>\n  <p class=\"hero-sub\">컨트롤러부터 예외 처리·검증·테스트까지 — <strong>한 기능을 끝까지 짜는</strong> 레시피. 개념 설명보다 실제로 동작하는 코드를 먼저 보고, 계층(Controller / Service / Repository)이 각자 무슨 책임을 지는지 손에 익히는 게 목표입니다. 프론트엔드에서 넘어온 감각으로 읽히게 썼습니다.</p>\n  <div class=\"hero-meta\">NOTE : Spring Boot 3.x 기준 — 패키지는 <code>jakarta.*</code>(구 <code>javax.*</code> 아님). 깊은 개념은 (→ 백엔드 개요), (→ 아키텍처 패턴) 참조<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"spring-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-01</span><h2>프로젝트 구조와 시작</h2></div>\n<p class=\"lede\">Spring Boot 앱의 출발점은 <code>main</code> 메서드 하나입니다 — 거기서 컨테이너가 뜨고, 패키지를 스캔해 객체들을 알아서 엮습니다. 프론트의 <code>index.tsx</code>처럼 \"여기가 시작\"인 파일을 먼저 잡으세요.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">Application.java — 진입점</span><br>\n<span class=\"seg2\">@SpringBootApplication</span><br>\n<span class=\"seg\">public class</span> AdminWorkflowApplication {<br>\n&nbsp;&nbsp;<span class=\"seg\">public static void</span> main(String[] args) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;SpringApplication.run(AdminWorkflowApplication.class, args);<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p><code>@SpringBootApplication</code>은 세 어노테이션을 묶은 것입니다 — <code>@SpringBootConfiguration</code>(설정 클래스), <code>@EnableAutoConfiguration</code>(의존성 보고 자동 설정), <code>@ComponentScan</code>(이 클래스가 있는 패키지 <em>아래</em>를 훑어 빈 등록). 그래서 진입점은 보통 <strong>최상위 패키지</strong>에 둡니다 — 아래에 있는 컴포넌트를 다 발견하도록.</p>\n<h3><span class=\"h3-tag\">1.1</span>패키지 계층</h3>\n<p>한 도메인을 네 층으로 나눕니다. 요청이 위에서 아래로 흐릅니다.</p>\n<div class=\"flow\">\n<span class=\"step hl\">controller</span><span class=\"arr\">→</span><span class=\"step\">service</span><span class=\"arr\">→</span><span class=\"step\">repository</span><span class=\"arr\">→</span><span class=\"step\">domain (DB)</span>\n</div>\n<table>\n<tr><th>패키지</th><th>책임</th></tr>\n<tr><td><code>controller</code></td><td>HTTP 요청·응답만. URL 매핑, 요청 파싱, 상태코드 결정. 비즈니스 로직 없음</td></tr>\n<tr><td><code>service</code></td><td>비즈니스 로직과 트랜잭션 경계. \"무엇을 한다\"가 여기 모임</td></tr>\n<tr><td><code>repository</code></td><td>DB 접근. 저장·조회 쿼리 (→ JPA 예시)</td></tr>\n<tr><td><code>domain</code></td><td>엔티티·도메인 모델. 데이터의 모양과 규칙</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">의존성 — starter</span>\n<p>Spring Boot는 개별 라이브러리 대신 <em>starter</em> 묶음으로 의존성을 받습니다. <code>spring-boot-starter-web</code>(REST·내장 Tomcat), <code>spring-boot-starter-data-jpa</code>(JPA·Hibernate), <code>spring-boot-starter-validation</code>(Bean Validation), <code>spring-boot-starter-test</code>(JUnit·Mockito·MockMvc). starter 하나가 호환되는 버전들을 한꺼번에 가져와서, 프론트의 <code>package.json</code>보다 버전 충돌 걱정이 적습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"spring-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-02</span><h2>REST 컨트롤러</h2></div>\n<p class=\"lede\">컨트롤러는 HTTP의 경계입니다 — URL과 메서드를 받아 service에 넘기고, 결과를 상태코드와 함께 돌려줍니다. Express의 라우터 핸들러와 같은 자리지만, 어노테이션으로 선언합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">UserController.java</span><br>\n<span class=\"seg2\">@RestController</span><br>\n<span class=\"seg2\">@RequestMapping(</span><span class=\"dim\">\"/api/users\"</span><span class=\"seg2\">)</span><br>\n<span class=\"seg\">public class</span> UserController {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">private final</span> UserService userService;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@GetMapping(</span><span class=\"dim\">\"/{id}\"</span><span class=\"seg2\">)</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> ResponseEntity&lt;UserResponse&gt; getUser(<span class=\"seg2\">@PathVariable</span> Long id) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;UserResponse user = userService.findById(id);<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> ResponseEntity.ok(user);&nbsp;&nbsp;<span class=\"dim\">// 200</span><br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@GetMapping</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> List&lt;UserResponse&gt; list(<span class=\"seg2\">@RequestParam(</span>defaultValue = <span class=\"dim\">\"0\"</span><span class=\"seg2\">)</span> int page) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> userService.findAll(page);<br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@PostMapping</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> ResponseEntity&lt;UserResponse&gt; create(<span class=\"seg2\">@RequestBody</span> CreateUserRequest req) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;UserResponse created = userService.create(req);<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> ResponseEntity.status(HttpStatus.CREATED).body(created);&nbsp;&nbsp;<span class=\"dim\">// 201</span><br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<table>\n<tr><th>어노테이션</th><th>역할</th></tr>\n<tr><td><code>@RestController</code></td><td><code>@Controller</code> + <code>@ResponseBody</code> — 반환값을 JSON 본문으로 직렬화</td></tr>\n<tr><td><code>@RequestMapping(\"/api/users\")</code></td><td>클래스 공통 prefix. 메서드 매핑이 이어붙음</td></tr>\n<tr><td><code>@GetMapping</code> / <code>@PostMapping</code> / <code>@PutMapping</code> / <code>@DeleteMapping</code></td><td>HTTP 메서드별 매핑. 조회·생성·교체·삭제</td></tr>\n<tr><td><code>@PathVariable</code></td><td>URL 경로의 값 (<code>/users/{id}</code>의 <code>id</code>)</td></tr>\n<tr><td><code>@RequestParam</code></td><td>쿼리 파라미터 (<code>?page=0</code>). <code>defaultValue</code>·<code>required</code> 지정 가능</td></tr>\n<tr><td><code>@RequestBody</code></td><td>요청 JSON 본문을 객체로 역직렬화</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">ResponseEntity vs 객체 직접 반환</span>\n<p>상태코드·헤더를 직접 정해야 하면 <code>ResponseEntity&lt;User&gt;</code>를, 항상 200이면 객체(<code>UserResponse</code> · <code>List&lt;UserResponse&gt;</code>)를 그냥 반환하면 됩니다. 생성은 <code>201 Created</code>, 본문 없는 삭제는 <code>ResponseEntity.noContent().build()</code>(204)가 관례입니다. 상태코드는 의미를 담으니 다 <code>200</code>으로 뭉뚱그리지 마세요(→ API 설계 원칙).</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"spring-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-03</span><h2>DI와 빈</h2></div>\n<p class=\"lede\">JS에서는 <code>new UserService()</code>로 직접 객체를 만들지만, Spring에서는 <em>컨테이너가 객체를 만들어 들고 있다가 필요한 곳에 넣어줍니다</em>. 이게 의존성 주입(DI)입니다. 당신은 \"이게 필요해\"라고 선언만 합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">생성자 주입 — 권장 방식</span><br>\n<span class=\"seg2\">@Service</span><br>\n<span class=\"seg\">public class</span> UserService {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">private final</span> UserRepository userRepository;<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// 생성자가 하나면 @Autowired 생략 가능 — 컨테이너가 알아서 주입</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> UserService(UserRepository userRepository) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">this</span>.userRepository = userRepository;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p><strong>생성자 주입</strong>이 권장입니다 — 필드를 <code>final</code>로 둘 수 있어 불변이고, 객체가 만들어질 때 의존성이 반드시 채워지며(누락 시 컴파일·기동 단계에서 발각), 테스트에서 <code>new UserService(mockRepo)</code>로 쉽게 갈아끼웁니다. 필드 주입(<code>@Autowired</code> 필드)은 이 장점들을 잃으니 피하세요.</p>\n<table>\n<tr><th>스테레오타입</th><th>붙이는 곳</th></tr>\n<tr><td><code>@Component</code></td><td>일반 빈. 아래 셋의 부모 — 특정 역할이 없을 때</td></tr>\n<tr><td><code>@Service</code></td><td>비즈니스 로직 계층. 의미상 service임을 표시</td></tr>\n<tr><td><code>@Repository</code></td><td>데이터 접근 계층. DB 예외를 Spring 예외로 변환해주는 효과도</td></tr>\n<tr><td><code>@RestController</code> / <code>@Controller</code></td><td>웹 계층 (위 셋과 같은 <code>@Component</code> 계열)</td></tr>\n</table>\n<h3><span class=\"h3-tag\">3.1</span>직접 만드는 빈 — @Configuration + @Bean</h3>\n<p>내가 코드를 소유하지 않은 외부 라이브러리 객체(예: <code>RestClient</code>)는 어노테이션을 못 붙입니다. 이럴 때 메서드로 빈을 직접 만들어 등록합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">AppConfig.java</span><br>\n<span class=\"seg2\">@Configuration</span><br>\n<span class=\"seg\">public class</span> AppConfig {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Bean</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> RestClient paymentApiClient() {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> RestClient.builder()<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.baseUrl(<span class=\"dim\">\"https://api.example.com\"</span>)<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.build();<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">사고 전환</span>\n<p>프론트에서는 모듈을 <code>import</code>하면 그 인스턴스를 내가 책임지고 만들고 관리합니다. Spring에서는 <em>객체의 생애주기를 컨테이너에 위임</em>합니다 — 기본적으로 빈은 싱글톤 하나로 관리되고, 어디서 주입받든 같은 인스턴스입니다. \"누가 이 객체를 만들고 들고 있나?\"의 답이 항상 컨테이너라는 점이 핵심 차이입니다(→ 아키텍처 패턴).</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"spring-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-04</span><h2>설정</h2></div>\n<p class=\"lede\">환경마다 다른 값(DB URL, 외부 키, 포트)을 코드에서 분리합니다. <code>.env</code>의 Spring 버전이 <code>application.yml</code>이고, 환경 분리는 profile로 합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">application.yml</span><br>\n<span class=\"seg2\">spring:</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">application:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;name: payment-service<br>\n&nbsp;&nbsp;<span class=\"seg2\">profiles:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;active: <span class=\"seg\">${SPRING_PROFILES_ACTIVE:local}</span>&nbsp;&nbsp;<span class=\"dim\"># 환경변수 없으면 local</span><br>\n<br>\n<span class=\"seg2\">payment:</span><br>\n&nbsp;&nbsp;trading:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;max-credit-per-tx: 10000<br>\n&nbsp;&nbsp;&nbsp;&nbsp;api-key: <span class=\"seg\">${PARTNER_API_KEY}</span>&nbsp;&nbsp;<span class=\"dim\"># secret은 환경변수로</span>\n</div>\n<h3><span class=\"h3-tag\">4.1</span>값 읽기 — @Value vs @ConfigurationProperties</h3>\n<table>\n<tr><th>방식</th><th>언제</th></tr>\n<tr><td><code>@Value(\"${payment.service.api-key}\")</code></td><td>값 한두 개를 필드에 바로 꽂을 때. 간단하지만 흩어짐</td></tr>\n<tr><td><code>@ConfigurationProperties(\"payment.service\")</code></td><td>관련 값 묶음을 <em>타입 안전한 객체</em>로. 묶음이 커지면 이쪽</td></tr>\n</table>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">@ConfigurationProperties — 묶음을 객체로</span><br>\n<span class=\"seg2\">@ConfigurationProperties(prefix = </span><span class=\"dim\">\"payment.service\"</span><span class=\"seg2\">)</span><br>\n<span class=\"seg\">public record</span> TradingProperties(<br>\n&nbsp;&nbsp;<span class=\"seg\">int</span> maxCreditPerTx,<br>\n&nbsp;&nbsp;String apiKey<br>\n) {}<br>\n<br>\n<span class=\"dim\">// 진입점이나 @Configuration에 @EnableConfigurationProperties(TradingProperties.class)</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">profile별 파일 분리</span>\n<p><code>application-{profile}.yml</code> 규칙으로 환경을 나눕니다 — <code>application-local.yml</code>, <code>application-prod.yml</code>. 공통값은 <code>application.yml</code>에 두고, 활성 profile 파일이 같은 키를 <em>덮어씁니다</em>. 활성화는 <code>spring.profiles.active</code> 또는 실행 시 <code>--spring.profiles.active=prod</code> / 환경변수 <code>SPRING_PROFILES_ACTIVE</code>.</p>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">SECRET</span>\n<p>API 키·DB 비밀번호를 <code>application.yml</code>에 <em>직접 박지 마세요</em>. <code>${PARTNER_API_KEY}</code>처럼 환경변수나 secret manager를 참조하고, 실제 값은 저장소 밖에 둡니다. yml에 평문으로 커밋된 secret은 git 히스토리에 영원히 남습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"spring-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-05</span><h2>서비스·트랜잭션</h2></div>\n<p class=\"lede\">service 계층이 비즈니스 로직의 집입니다. 그리고 여기서 <em>트랜잭션 경계</em>를 긋습니다 — \"이 메서드 안의 DB 작업은 전부 성공하거나, 전부 롤백된다\".</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">UserService.java — 트랜잭션 경계</span><br>\n<span class=\"seg2\">@Service</span><br>\n<span class=\"seg\">public class</span> UserService {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">private final</span> UserRepository userRepository;<br>\n&nbsp;&nbsp;<span class=\"dim\">// 생성자 생략</span><br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Transactional(readOnly = true)</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> UserResponse findById(Long id) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;User user = userRepository.findById(id)<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.orElseThrow(() -&gt; <span class=\"seg\">new</span> UserNotFoundException(id));<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> UserResponse.from(user);<br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Transactional</span>&nbsp;&nbsp;<span class=\"dim\">// 쓰기 — 중간에 실패하면 전부 롤백</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> UserResponse create(CreateUserRequest req) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">if</span> (userRepository.existsByEmail(req.email())) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">throw new</span> DuplicateEmailException(req.email());<br>\n&nbsp;&nbsp;&nbsp;&nbsp;}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;User saved = userRepository.save(req.toEntity());<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> UserResponse.from(saved);<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<table>\n<tr><th>요소</th><th>의미</th></tr>\n<tr><td><code>@Transactional</code></td><td>메서드 시작~끝을 한 트랜잭션으로. 정상 종료 시 commit, 예외 전파 시 rollback</td></tr>\n<tr><td><code>readOnly = true</code></td><td>조회 전용 — 쓰기 안 함을 명시. 성능 힌트(flush 생략 등)이자 의도 표현</td></tr>\n<tr><td>throw로 롤백</td><td>기본은 <em>unchecked 예외</em>(RuntimeException)에서 롤백. service에서 던진 도메인 예외가 롤백을 유발</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">트랜잭션은 service에, controller에 두지 말 것</span>\n<p>트랜잭션 경계는 \"하나의 비즈니스 작업\" 단위여야 합니다 — 그래서 service 메서드에 둡니다. controller에 <code>@Transactional</code>을 붙이면 HTTP·직렬화까지 트랜잭션 안에 들어와 경계가 흐려집니다. 또 <strong>같은 클래스 내부 메서드 호출은 <code>@Transactional</code>이 안 먹습니다</strong> — Spring AOP 프록시가 외부 진입점에서만 가로채기 때문입니다(→ 아키텍처 패턴).</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"spring-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-06</span><h2>예외 처리</h2></div>\n<p class=\"lede\">각 컨트롤러에서 <code>try-catch</code>를 반복하지 마세요. service는 도메인 예외를 던지고, <em>한 곳에서</em> 잡아 일관된 에러 응답으로 변환합니다. 프론트의 전역 에러 바운더리에 가깝습니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">ErrorResponse.java — 표준 에러 DTO</span><br>\n<span class=\"seg\">public record</span> ErrorResponse(<br>\n&nbsp;&nbsp;String code,<br>\n&nbsp;&nbsp;String message,<br>\n&nbsp;&nbsp;Instant timestamp<br>\n) {<br>\n&nbsp;&nbsp;<span class=\"seg\">public static</span> ErrorResponse of(String code, String message) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return new</span> ErrorResponse(code, message, Instant.now());<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">GlobalExceptionHandler.java</span><br>\n<span class=\"seg2\">@RestControllerAdvice</span><br>\n<span class=\"seg\">public class</span> GlobalExceptionHandler {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@ExceptionHandler(UserNotFoundException.class)</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> ResponseEntity&lt;ErrorResponse&gt; handleNotFound(UserNotFoundException e) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> ResponseEntity.status(HttpStatus.NOT_FOUND)&nbsp;&nbsp;<span class=\"dim\">// 404</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.body(ErrorResponse.of(<span class=\"dim\">\"USER_NOT_FOUND\"</span>, e.getMessage()));<br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@ExceptionHandler(DuplicateEmailException.class)</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public</span> ResponseEntity&lt;ErrorResponse&gt; handleDuplicate(DuplicateEmailException e) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">return</span> ResponseEntity.status(HttpStatus.CONFLICT)&nbsp;&nbsp;<span class=\"dim\">// 409</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.body(ErrorResponse.of(<span class=\"dim\">\"DUPLICATE_EMAIL\"</span>, e.getMessage()));<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<table>\n<tr><th>요소</th><th>역할</th></tr>\n<tr><td><code>@RestControllerAdvice</code></td><td>모든 컨트롤러에 걸치는 전역 예외 처리. 응답은 JSON</td></tr>\n<tr><td><code>@ExceptionHandler(X.class)</code></td><td>특정 예외 타입을 잡아 응답으로 변환하는 메서드</td></tr>\n<tr><td>4xx (클라이언트 잘못)</td><td>잘못된 입력·없는 리소스·중복 — 도메인 예외를 매핑</td></tr>\n<tr><td>5xx (서버 잘못)</td><td>예기치 못한 버그·외부 장애. 마지막에 <code>Exception.class</code>로 받아 500</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">에러를 삼키지 말 것</span>\n<p>5xx로 내려갈 예외는 클라이언트에 내부 stack trace·SQL을 노출하지 말고, 로그에는 전부 남기세요 — 사용자에게 보여줄 메시지와 로그 메시지를 분리합니다. <em>expected failure</em>(중복 이메일 같은 도메인 규칙)는 4xx로 명확히, <em>bug</em>(NPE 등)는 5xx로 잡되 알람이 울리게. 빈 <code>catch</code>로 예외를 묻으면 디버깅이 불가능해집니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"spring-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-07</span><h2>요청 검증</h2></div>\n<p class=\"lede\">잘못된 입력은 service에 닿기 전에 막습니다. DTO에 제약을 어노테이션으로 선언하고, 컨트롤러에서 <code>@Valid</code>로 발동시키면 Spring이 자동으로 검사합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">CreateUserRequest.java — Bean Validation</span><br>\n<span class=\"seg\">public record</span> CreateUserRequest(<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@NotBlank</span>&nbsp;&nbsp;<span class=\"dim\">// null·빈문자·공백 모두 거부</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@Size(max = 50)</span><br>\n&nbsp;&nbsp;String name,<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@NotBlank</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@Email</span>&nbsp;&nbsp;<span class=\"dim\">// 이메일 형식</span><br>\n&nbsp;&nbsp;String email,<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@NotNull</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@Positive</span>&nbsp;&nbsp;<span class=\"dim\">// 0보다 큰 값</span><br>\n&nbsp;&nbsp;Integer creditBalance<br>\n) {}\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">컨트롤러에서 @Valid로 발동</span><br>\n<span class=\"seg2\">@PostMapping</span><br>\n<span class=\"seg\">public</span> ResponseEntity&lt;UserResponse&gt; create(<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Valid</span> <span class=\"seg2\">@RequestBody</span> CreateUserRequest req&nbsp;&nbsp;<span class=\"dim\">// 검증 실패 시 자동으로 예외</span><br>\n) {<br>\n&nbsp;&nbsp;<span class=\"seg\">return</span> ResponseEntity.status(HttpStatus.CREATED).body(userService.create(req));<br>\n}\n</div>\n<table>\n<tr><th>제약</th><th>의미</th></tr>\n<tr><td><code>@NotNull</code></td><td>null만 거부 (빈 문자열·0은 통과)</td></tr>\n<tr><td><code>@NotBlank</code></td><td>문자열 전용 — null·\"\"·공백만 모두 거부</td></tr>\n<tr><td><code>@Size(min=, max=)</code></td><td>문자열 길이·컬렉션 크기 범위</td></tr>\n<tr><td><code>@Email</code></td><td>이메일 형식</td></tr>\n<tr><td><code>@NotNull</code> + <code>@Positive</code> / <code>@Min</code></td><td>숫자 범위. <code>@Positive</code>는 0 초과</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">검증 실패도 GlobalExceptionHandler에서 처리</span>\n<p><code>@Valid</code> 검증이 실패하면 <code>MethodArgumentNotValidException</code>이 던져집니다. 이것도 ch6의 <code>@RestControllerAdvice</code>에서 한 번에 잡아 400으로 변환하면, 검증 에러까지 같은 <code>ErrorResponse</code> 포맷으로 일관됩니다.</p>\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">검증 에러 → 400으로 변환</span><br>\n<span class=\"seg2\">@ExceptionHandler(MethodArgumentNotValidException.class)</span><br>\n<span class=\"seg\">public</span> ResponseEntity&lt;ErrorResponse&gt; handleValidation(MethodArgumentNotValidException e) {<br>\n&nbsp;&nbsp;String message = e.getBindingResult().getFieldErrors().stream()<br>\n&nbsp;&nbsp;&nbsp;&nbsp;.map(fe -&gt; fe.getField() + <span class=\"dim\">\": \"</span> + fe.getDefaultMessage())<br>\n&nbsp;&nbsp;&nbsp;&nbsp;.collect(Collectors.joining(<span class=\"dim\">\", \"</span>));<br>\n&nbsp;&nbsp;<span class=\"seg\">return</span> ResponseEntity.badRequest()&nbsp;&nbsp;<span class=\"dim\">// 400</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;.body(ErrorResponse.of(<span class=\"dim\">\"VALIDATION_FAILED\"</span>, message));<br>\n}\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"spring-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-08</span><h2>데이터 접근 연동</h2></div>\n<p class=\"lede\">service는 DB를 직접 만지지 않고 repository에 위임합니다. repository는 인터페이스만 선언하면 Spring Data JPA가 구현체를 자동으로 만들어줍니다 — 여기서는 <em>연동 흐름</em>만 보고, 쿼리 작성은 (→ JPA 예시).</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">UserRepository.java — 인터페이스만</span><br>\n<span class=\"seg2\">@Repository</span><br>\n<span class=\"seg\">public interface</span> UserRepository <span class=\"seg\">extends</span> JpaRepository&lt;User, Long&gt; {<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// 메서드 이름만으로 쿼리 생성 — 구현 불필요</span><br>\n&nbsp;&nbsp;<span class=\"seg\">boolean</span> existsByEmail(String email);<br>\n&nbsp;&nbsp;Optional&lt;User&gt; findByEmail(String email);<br>\n}\n</div>\n<p><code>JpaRepository&lt;User, Long&gt;</code>를 확장하면 <code>save</code>·<code>findById</code>·<code>findAll</code>·<code>delete</code> 같은 기본 CRUD가 공짜로 생깁니다(엔티티 <code>User</code>, PK 타입 <code>Long</code>). service에서는 이걸 주입받아 그냥 호출하면 됩니다.</p>\n<div class=\"flow\">\n<span class=\"step\">UserController</span><span class=\"arr\">→</span><span class=\"step hl\">UserService</span><span class=\"arr\">→</span><span class=\"step\">UserRepository</span><span class=\"arr\">→</span><span class=\"step\">DB</span>\n</div>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">service에서 repository 사용 (ch5 재방문)</span><br>\n<span class=\"seg2\">@Transactional(readOnly = true)</span><br>\n<span class=\"seg\">public</span> List&lt;UserResponse&gt; findAll(int page) {<br>\n&nbsp;&nbsp;<span class=\"seg\">return</span> userRepository.findAll(PageRequest.of(page, 20))<br>\n&nbsp;&nbsp;&nbsp;&nbsp;.map(UserResponse::from)<br>\n&nbsp;&nbsp;&nbsp;&nbsp;.getContent();<br>\n}\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">엔티티를 컨트롤러로 흘리지 말 것</span>\n<p>DB 엔티티(<code>User</code>)를 그대로 응답으로 반환하지 말고 <code>UserResponse</code> 같은 DTO로 변환해 내보내세요 — 엔티티를 노출하면 내부 필드·연관관계가 새어 나가고, JSON 직렬화 중 lazy loading 문제가 생깁니다. 쿼리 메서드 작명 규칙·연관관계·N+1 같은 본격적인 내용은 (→ JPA 예시)에서 다룹니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"spring-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-09</span><h2>테스트</h2></div>\n<p class=\"lede\">전부 띄울지(<code>@SpringBootTest</code>), 웹 계층만 잘라 빠르게 볼지(<code>@WebMvcTest</code>)를 먼저 고릅니다. 컨트롤러 검증·매핑 테스트는 슬라이스가 빠르고 충분합니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">UserControllerTest.java — @WebMvcTest 슬라이스</span><br>\n<span class=\"seg2\">@WebMvcTest(UserController.class)</span>&nbsp;&nbsp;<span class=\"dim\">// 웹 계층만 로드 — 빠름</span><br>\n<span class=\"seg\">class</span> UserControllerTest {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Autowired</span> MockMvc mockMvc;<br>\n&nbsp;&nbsp;<span class=\"seg2\">@MockBean</span> UserService userService;&nbsp;&nbsp;<span class=\"dim\">// service는 가짜로 대체</span><br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Test</span><br>\n&nbsp;&nbsp;<span class=\"seg\">void</span> 존재하는_id로_조회하면_200과_유저를_반환한다() <span class=\"seg\">throws</span> Exception {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;given(userService.findById(1L))<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.willReturn(<span class=\"seg\">new</span> UserResponse(1L, <span class=\"dim\">\"haeun\"</span>, <span class=\"dim\">\"a@b.com\"</span>));<br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;mockMvc.perform(get(<span class=\"dim\">\"/api/users/1\"</span>))<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.andExpect(status().isOk())<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;.andExpect(jsonPath(<span class=\"dim\">\"$.name\"</span>).value(<span class=\"dim\">\"haeun\"</span>));<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<table>\n<tr><th>방식</th><th>로드 범위 / 언제</th></tr>\n<tr><td><code>@SpringBootTest</code></td><td>전체 컨텍스트를 띄움. 통합 테스트 — 실제 흐름 검증, 느림</td></tr>\n<tr><td><code>@WebMvcTest(X.class)</code></td><td>지정 컨트롤러 + 웹 계층만. service는 <code>@MockBean</code>으로 대체</td></tr>\n<tr><td><code>MockMvc</code></td><td>실제 서버 없이 HTTP 요청을 흉내 — 매핑·상태코드·JSON 검증</td></tr>\n<tr><td><code>@MockBean</code></td><td>컨텍스트의 빈을 Mockito 가짜로 교체. 의존성 격리</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">무엇을 어느 레벨에서 테스트할까</span>\n<p>컨트롤러는 <code>@WebMvcTest</code> + <code>MockMvc</code>로 매핑·검증·상태코드를, service는 순수 단위 테스트로 비즈니스 로직을(생성자 주입이면 <code>new</code>로 mock을 넣어 Spring 없이도 가능), 전체 연동은 소수의 <code>@SpringBootTest</code>로. <em>동작을 테스트하고 내부 호출 횟수 같은 구현 디테일은 피하세요.</em> 테스트 이름은 \"어떤 조건에서 어떤 결과\"가 문장으로 읽히게.</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"spring-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-10</span><h2>운영 — Actuator</h2></div>\n<p class=\"lede\">배포한 앱이 살아있는지, 어떤 상태인지를 들여다보는 창입니다. <code>spring-boot-starter-actuator</code>를 추가하면 운영용 엔드포인트가 열립니다 — 로드밸런서·쿠버네티스 헬스체크의 표적이 됩니다.</p>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">application.yml — 노출 엔드포인트 선택</span><br>\n<span class=\"seg2\">management:</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">endpoints:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;web:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;exposure:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;include: health, info, metrics&nbsp;&nbsp;<span class=\"dim\"># 필요한 것만 명시</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">endpoint:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;health:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;show-details: when-authorized\n</div>\n<table>\n<tr><th>엔드포인트</th><th>역할</th></tr>\n<tr><td><code>GET /actuator/health</code></td><td>앱·DB·디스크 상태. <code>{\"status\":\"UP\"}</code> — 헬스체크의 핵심</td></tr>\n<tr><td><code>GET /actuator/info</code></td><td>빌드·버전 등 임의 메타 정보</td></tr>\n<tr><td><code>GET /actuator/metrics</code></td><td>JVM 메모리·요청 수·응답 시간 등 지표. 모니터링 연동</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">엔드포인트 노출 범위 주의</span>\n<p>Actuator 엔드포인트는 운영 정보를 담으니 <em>전부 공개하지 마세요</em>. 기본은 <code>health</code>·<code>info</code>만 노출되고, <code>include: \"*\"</code>로 전체를 열면 <code>env</code>·<code>heapdump</code> 같은 민감 정보까지 새어나갑니다. 필요한 것만 명시하고, 외부 노출 시에는 인증으로 보호하세요(→ 백엔드 개요의 관측가능성).</p>\n</div>\n</section>\n\n<!-- ============ CH 11 ============ -->\n<section id=\"spring-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-11</span><h2>치트시트</h2></div>\n<p class=\"lede\">한 기능을 짤 때 반복되는 핵심들. 외우기보다 \"이 자리엔 이게 온다\"는 감각으로 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>진입점</b><span>@SpringBootApplication</span></div><div class=\"g-def\">최상위 패키지에 두고 <code>SpringApplication.run(...)</code>. 아래 패키지를 스캔해 빈 등록</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>컨트롤러 매핑</b><span>@RestController</span></div><div class=\"g-def\"><code>@GetMapping</code>/<code>@PostMapping</code>/<code>@PutMapping</code>/<code>@DeleteMapping</code> + <code>@PathVariable</code>/<code>@RequestParam</code>/<code>@RequestBody</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>응답 제어</b><span>ResponseEntity</span></div><div class=\"g-def\">상태코드·헤더를 직접 정할 때 <code>ResponseEntity&lt;T&gt;</code>. 항상 200이면 객체를 그냥 반환</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>DI</b><span>생성자 주입 + final</span></div><div class=\"g-def\">생성자 하나면 <code>@Autowired</code> 생략. 필드 주입 대신 생성자 주입이 권장</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>스테레오타입</b><span>@Service / @Repository</span></div><div class=\"g-def\">계층 표시 어노테이션. 외부 객체는 <code>@Configuration</code> + <code>@Bean</code>으로 직접 등록</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>설정 값</b><span>application.yml</span></div><div class=\"g-def\">한두 개는 <code>@Value</code>, 묶음은 <code>@ConfigurationProperties</code>. secret은 <code>${ENV_VAR}</code>로</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>환경 분리</b><span>profile</span></div><div class=\"g-def\"><code>application-{profile}.yml</code> + <code>spring.profiles.active</code>로 local/prod 전환</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>트랜잭션</b><span>@Transactional</span></div><div class=\"g-def\">service 메서드에. 조회는 <code>readOnly = true</code>. 같은 클래스 내부 호출엔 안 먹음(프록시)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>예외 처리</b><span>@RestControllerAdvice</span></div><div class=\"g-def\">+ <code>@ExceptionHandler</code>로 전역 변환. 4xx(클라이언트)·5xx(서버)를 표준 <code>ErrorResponse</code>로</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>요청 검증</b><span>@Valid</span></div><div class=\"g-def\">DTO에 <code>@NotBlank</code>/<code>@Size</code>/<code>@Email</code> 선언 + 컨트롤러에서 <code>@Valid</code>. 실패는 <code>MethodArgumentNotValidException</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>데이터 접근</b><span>JpaRepository</span></div><div class=\"g-def\">인터페이스만 확장하면 CRUD 자동. 엔티티 말고 DTO로 응답 (→ JPA 예시)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>컨트롤러 테스트</b><span>@WebMvcTest + MockMvc</span></div><div class=\"g-def\">웹 계층만 로드, service는 <code>@MockBean</code>. 전체는 <code>@SpringBootTest</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>운영 점검</b><span>Actuator</span></div><div class=\"g-def\"><code>/actuator/health</code>·<code>info</code>·<code>metrics</code>. 노출 범위는 좁게, 민감 엔드포인트는 인증으로</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">한 기능을 끝까지 — 짜는 순서</span>\n<p>① 요청·응답 DTO(검증 어노테이션 포함) → ② 컨트롤러(매핑·상태코드) → ③ service(<code>@Transactional</code>·비즈니스 로직) → ④ repository(주입해 호출) → ⑤ 도메인 예외 + <code>@RestControllerAdvice</code> → ⑥ <code>@WebMvcTest</code>로 컨트롤러, 단위 테스트로 service. 이 한 바퀴를 손에 넣으면 새 기능마다 같은 골격을 반복하면 됩니다. 계층의 책임 분리가 왜 중요한지, 더 큰 구조는 (→ 아키텍처 패턴)에서.</p>\n</div>\n</section>\n\n<section id=\"spring-ch12\">\n<div class=\"ch-head\"><span class=\"ch-code\">SPRING-12</span><h2>프록시·트랜잭션·테스트 심화</h2></div>\n<p class=\"lede\">Spring을 깊게 이해한다는 것은 어노테이션을 많이 아는 것이 아니라, 컨테이너가 만든 프록시 객체를 통해 부가기능이 적용된다는 사실을 이해하는 것입니다. <code>@Transactional</code>, 보안, 캐시, 로깅 AOP가 모두 이 사고 위에 있습니다.</p>\n<table>\n<tr><th>개념</th><th>정확한 의미</th><th>면접 단골 함정</th></tr>\n<tr><td>Bean</td><td>Spring container가 생성·관리하는 객체</td><td>new로 만든 객체에는 DI/AOP가 적용되지 않음</td></tr>\n<tr><td>Proxy</td><td>실제 객체 앞에서 트랜잭션 같은 부가기능을 감싸는 대리 객체</td><td>같은 클래스 내부 메서드 호출(self-invocation)은 프록시를 거치지 않음</td></tr>\n<tr><td>@Transactional</td><td>프록시가 메서드 전후로 transaction begin/commit/rollback을 처리</td><td>private 메서드, 내부 호출, checked exception rollback 정책 오해</td></tr>\n<tr><td>readOnly</td><td>읽기 트랜잭션 힌트, flush 최적화와 의도 표현</td><td>DB가 모든 쓰기를 자동 차단한다고 착각</td></tr>\n<tr><td>@ControllerAdvice</td><td>예외를 HTTP error contract로 번역하는 경계</td><td>모든 예외를 500으로 뭉개거나 문자열 message만 반환</td></tr>\n<tr><td>Slice Test</td><td>웹, JPA 등 특정 계층만 로드하는 빠른 테스트</td><td>모든 테스트를 @SpringBootTest로 돌려 느리고 깨지기 쉬움</td></tr>\n</table>\n<div class=\"semantic-card process-card\">\n<span class=\"sc-label\">TRANSACTION PROXY FLOW</span><br>\nclient → proxy.findUser()<br>\nproxy: begin transaction<br>\ntarget service method 실행<br>\nproxy: 정상 return이면 commit, runtime exception이면 rollback<br>\n<span class=\"dim\">this.otherTransactionalMethod() 는 proxy를 거치지 않으므로 새 트랜잭션 속성이 적용되지 않는다.</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">rollback 정책</span>\n<p>Spring의 기본 <code>@Transactional</code>은 unchecked exception(RuntimeException, Error)에서 rollback하고 checked exception은 기본적으로 rollback하지 않습니다. 비즈니스 예외를 checked로 만들었다면 <code>rollbackFor</code>를 명시해야 할 수 있습니다. 면접에서 “예외가 나면 롤백됩니다”로 끝내면 부족하고, 어떤 예외인지와 트랜잭션 경계가 어디인지까지 말해야 합니다.</p>\n</div>\n<h3>테스트 경계</h3>\n<table>\n<tr><th>테스트</th><th>검증할 것</th><th>피해야 할 것</th></tr>\n<tr><td>Domain unit</td><td>상태 전이, 불변식, 계산 규칙</td><td>Spring context 로딩</td></tr>\n<tr><td>Service unit</td><td>유스케이스 분기, repository port 호출, 예외 처리</td><td>DB 세부 구현 검증</td></tr>\n<tr><td>@WebMvcTest</td><td>HTTP mapping, validation, status code, error body</td><td>service 내부 로직 검증</td></tr>\n<tr><td>@DataJpaTest</td><td>repository query, mapping, constraint</td><td>mock DB로 SQL 문제 숨기기</td></tr>\n<tr><td>@SpringBootTest</td><td>실제 wiring, 전체 흐름, 설정 통합</td><td>모든 edge case를 통합 테스트로만 검증</td></tr>\n</table>\n<div class=\"semantic-card answer-card\"><span class=\"sc-label\">SPRING DEPTH ANSWER</span><br>Spring의 @Transactional은 메서드에 마법이 걸리는 게 아니라 Spring bean을 감싼 proxy가 호출 전후로 트랜잭션을 시작하고 종료하는 구조입니다. 그래서 같은 클래스 내부 호출은 proxy를 거치지 않아 트랜잭션 속성이 적용되지 않을 수 있고, 기본 rollback은 unchecked exception 기준입니다. 테스트도 이 구조를 기준으로 domain은 순수 단위 테스트, web은 @WebMvcTest, repository는 @DataJpaTest, wiring은 소수의 @SpringBootTest로 나눕니다.</div>\n</section>\n\n<footer>\nSPRING BOOT 예시 사례 · V1 · 2026-06<br>\nSTACK : SPRING BOOT 3.x (jakarta.*) · JPA · BEAN VALIDATION · ACTUATOR<br>\nNOTE : 코드는 레시피 — 개념 깊이는 백엔드 개요·아키텍처 패턴, 데이터 접근은 JPA 예시 참조\n</footer>",
};

export default document;
